import React, { useState, useEffect, useMemo } from 'react';
import { AppTab, CartItem, FoodItem } from './types';
import { FOOD_ITEMS, MOCK_USER } from './constants';
import HomeTab from './components/HomeTab';
import OrderTab from './components/OrderTab';
import ProfileTab from './components/ProfileTab';
import BottomNav from './components/BottomNav';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>('home');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isInstalled, setIsInstalled] = useState(false);
  const [showNotification, setShowNotification] = useState<string | null>(null);

  // Cart logic
  const addToCart = (item: FoodItem) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      }
      return [...prev, { ...item, quantity: 1 }];
    });
    triggerNotification(`${item.name} added to cart!`);
  };

  const removeFromCart = (itemId: string) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === itemId);
      if (existing && existing.quantity > 1) {
        return prev.map(i => i.id === itemId ? { ...i, quantity: i.quantity - 1 } : i);
      }
      return prev.filter(i => i.id !== itemId);
    });
  };

  const clearCart = () => setCart([]);

  const triggerNotification = (msg: string) => {
    setShowNotification(msg);
    setTimeout(() => setShowNotification(null), 3000);
  };

  const handleInstall = () => {
    setIsInstalled(true);
    triggerNotification("Hotel Anandam installed successfully!");
  };

  return (
    <div className="flex flex-col h-screen max-w-md mx-auto bg-white shadow-2xl overflow-hidden relative border-x border-gray-100">

      {/* Header */}
      <header className="bg-orange-500 text-white px-6 py-4 flex items-center justify-between shadow-md z-20">
        <div>
          <h1 className="text-xl font-bold tracking-tight">Hotel Anandam</h1>
          <p className="text-xs text-orange-100 flex items-center">
            <i className="fas fa-map-marker-alt mr-1"></i> Madurai, TN
          </p>
        </div>
        {!isInstalled && (
          <button 
            onClick={handleInstall}
            className="bg-white text-orange-500 px-3 py-1.5 rounded-full text-xs font-semibold shadow-sm hover:bg-orange-50 transition-colors"
          >
            <i className="fas fa-download mr-1"></i> Install
          </button>
        )}
      </header>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto custom-scrollbar bg-gray-50 pb-20">
        {activeTab === 'home' && (
          <HomeTab 
            items={FOOD_ITEMS} 
            onAdd={addToCart} 
            onInstall={handleInstall}
            isInstalled={isInstalled}
          />
        )}
        {activeTab === 'order' && (
          <OrderTab 
            cartItems={cart} 
            onAdd={addToCart} 
            onRemove={removeFromCart}
            onClear={clearCart}
            onPlaced={() => setActiveTab('order')}
          />
        )}
        {activeTab === 'profile' && (
          <ProfileTab user={MOCK_USER} />
        )}
      </main>

      {/* Notification Toast */}
      {showNotification && (
        <div className="fixed bottom-24 left-1/2 -translate-x-1/2 bg-gray-800 text-white px-4 py-2 rounded-lg text-sm shadow-xl z-50 animate-bounce">
          {showNotification}
        </div>
      )}

      {/* Bottom Navigation */}
      <BottomNav 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        cartCount={cart.reduce((acc, curr) => acc + curr.quantity, 0)}
      />
    </div>
  );
};

export default App;

