import React, { useState } from 'react';
import { CartItem, FoodItem } from '../types';

interface OrderTabProps {
  cartItems: CartItem[];
  onAdd: (item: FoodItem) => void;
  onRemove: (itemId: string) => void;
  onClear: () => void;
  onPlaced: () => void;
}

const OrderTab: React.FC<OrderTabProps> = ({ cartItems, onAdd, onRemove, onClear, onPlaced }) => {
  const [orderStatus, setOrderStatus] = useState<'idle' | 'processing' | 'success'>('idle');

  const subtotal = cartItems.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const deliveryFee = subtotal > 0 ? 30 : 0;
  const total = subtotal + deliveryFee;

  const handlePlaceOrder = () => {
    if (cartItems.length === 0) return;
    setOrderStatus('processing');
    setTimeout(() => {
      setOrderStatus('success');
      onClear();
      onPlaced();
    }, 2000);
  };

  if (orderStatus === 'processing') {
    return (
      <div className="flex flex-col items-center justify-center h-full p-6 text-center">
        <div className="w-16 h-16 border-4 border-orange-500 border-t-transparent rounded-full animate-spin mb-4"></div>
        <h3 className="text-xl font-bold text-gray-800">Processing Order</h3>
        <p className="text-gray-500">Contacting Hotel Anandam kitchen...</p>
      </div>
    );
  }

  if (orderStatus === 'success') {
    return (
      <div className="flex flex-col items-center justify-center h-full p-6 text-center animate-in fade-in zoom-in duration-500">
        <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center text-3xl mb-4">
          <i className="fas fa-check"></i>
        </div>
        <h3 className="text-2xl font-bold text-gray-800">Order Placed!</h3>
        <p className="text-gray-500 mt-2">Your delicious food is being prepared. It will reach you in 30-40 mins.</p>
        <button 
          onClick={() => setOrderStatus('idle')}
          className="mt-6 bg-orange-500 text-white px-8 py-3 rounded-xl font-bold shadow-lg shadow-orange-200 active:scale-95 transition-transform"
        >
          Track My Order
        </button>
      </div>
    );
  }

  return (
    <div className="p-4 flex flex-col h-full">
      <h3 className="text-2xl font-bold text-gray-800 mb-6">Your Cart</h3>

      {cartItems.length === 0 ? (
        <div className="flex-1 flex flex-col items-center justify-center text-gray-400 py-10">
          <i className="fas fa-shopping-basket text-6xl mb-4 opacity-20"></i>
          <p className="font-medium text-lg">Your basket is empty</p>
          <p className="text-sm">Add some delicious items from the menu!</p>
        </div>
      ) : (
        <div className="flex-1 space-y-4">
          <div className="space-y-4 max-h-[50vh] overflow-y-auto pr-1 custom-scrollbar">
            {cartItems.map(item => (
              <div key={item.id} className="bg-white p-3 rounded-xl border border-gray-100 flex items-center shadow-sm">
                <img src={item.image} alt={item.name} className="w-16 h-16 rounded-lg object-cover" />
                <div className="ml-4 flex-1">
                  <h4 className="font-bold text-gray-800">{item.name}</h4>
                  <p className="text-orange-600 font-bold text-sm">₹{item.price}</p>
                </div>
                <div className="flex items-center space-x-3 bg-gray-50 rounded-full px-2 py-1">
                  <button 
                    onClick={() => onRemove(item.id)}
                    className="w-7 h-7 bg-white text-gray-400 rounded-full flex items-center justify-center border border-gray-200"
                  >
                    <i className="fas fa-minus text-[10px]"></i>
                  </button>
                  <span className="font-bold text-gray-700 w-4 text-center text-sm">{item.quantity}</span>
                  <button 
                    onClick={() => onAdd(item)}
                    className="w-7 h-7 bg-orange-500 text-white rounded-full flex items-center justify-center shadow-sm"
                  >
                    <i className="fas fa-plus text-[10px]"></i>
                  </button>
                </div>
              </div>
            ))}
          </div>

          <div className="mt-8 bg-white rounded-2xl p-5 border border-gray-100 space-y-3 shadow-sm">
            <div className="flex justify-between text-sm text-gray-500">
              <span>Subtotal</span>
              <span>₹{subtotal}</span>
            </div>
            <div className="flex justify-between text-sm text-gray-500">
              <span>Delivery Fee</span>
              <span>₹{deliveryFee}</span>
            </div>
            <div className="h-px bg-gray-100 w-full"></div>
            <div className="flex justify-between text-lg font-bold text-gray-800">
              <span>Total</span>
              <span className="text-orange-600">₹{total}</span>
            </div>

            <button 
              onClick={handlePlaceOrder}
              className="w-full bg-orange-500 text-white py-4 rounded-xl font-bold text-lg mt-4 shadow-lg shadow-orange-100 hover:bg-orange-600 active:scale-95 transition-all"
            >
              Place Order
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default OrderTab;

