import React, { useState } from 'react';
import { CartItem, FoodItem } from '../types';

interface OrderTabProps {
  cartItems: CartItem[];
  onAdd: (item: FoodItem) => void;
  onRemove: (itemId: string) => void;
  onClear: () => void;
  onPlaced: () => void;
}

const OrderTab: React.FC<OrderTabProps> = ({ cartItems, onAdd, onRemove, onClear, onPlaced }) => {
  const [orderStatus, setOrderStatus] = useState<'idle' | 'processing' | 'success'>('idle');

  const subtotal = cartItems.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const deliveryFee = subtotal > 0 ? 30 : 0;
  const total = subtotal + deliveryFee;

  const handlePlaceOrder = () => {
    if (cartItems.length === 0) return;
    setOrderStatus('processing');
    setTimeout(() => {
      setOrderStatus('success');
      onClear();
      onPlaced();
    }, 2000);
  };

  if (orderStatus === 'processing') {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] p-6 text-center">
        <div className="w-20 h-20 border-4 border-orange-500 border-t-transparent rounded-full animate-spin mb-6"></div>
        <h3 className="text-2xl font-bold text-gray-800">Sending to Kitchen</h3>
        <p className="text-gray-500 mt-2">Hotel Anandam is getting your feast ready...</p>
      </div>
    );
  }

  if (orderStatus === 'success') {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] p-6 text-center animate-in fade-in zoom-in duration-500">
        <div className="w-24 h-24 bg-green-100 text-green-600 rounded-full flex items-center justify-center text-4xl mb-6 shadow-xl shadow-green-50">
          <i className="fas fa-check"></i>
        </div>
        <h3 className="text-3xl font-bold text-gray-800">Order Placed!</h3>
        <p className="text-gray-500 mt-4 max-w-sm text-lg">Your order from Hotel Anandam is being prepared with love. Expect delivery in 30-40 mins.</p>
        <button 
          onClick={() => setOrderStatus('idle')}
          className="mt-10 bg-orange-500 text-white px-12 py-4 rounded-2xl font-bold text-lg shadow-xl shadow-orange-200 active:scale-95 transition-all hover:bg-orange-600"
        >
          Track My Order
        </button>
      </div>
    );
  }

  return (
    <div className="p-4 sm:p-8 lg:p-12">
      <h3 className="text-3xl font-extrabold text-gray-800 mb-8">Checkout</h3>

      {cartItems.length === 0 ? (
        <div className="flex flex-col items-center justify-center text-gray-400 py-20 bg-white rounded-3xl border border-dashed border-gray-200">
          <div className="w-24 h-24 bg-gray-50 rounded-full flex items-center justify-center mb-6">
            <i className="fas fa-shopping-basket text-4xl opacity-30"></i>
          </div>
          <p className="font-bold text-xl text-gray-600">Your basket is empty</p>
          <p className="text-gray-400 mt-1">Go back and discover something delicious!</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 items-start">

          {/* Left Column: Cart Items */}
          <div className="lg:col-span-2 space-y-4">
            <div className="bg-white rounded-3xl p-6 shadow-sm border border-gray-100">
              <div className="flex items-center justify-between mb-6">
                <h4 className="font-bold text-gray-800 text-lg">Items in Basket ({cartItems.length})</h4>
                <button onClick={onClear} className="text-xs font-bold text-red-400 hover:text-red-500 uppercase tracking-wider">Clear All</button>
              </div>
              <div className="space-y-6">
                {cartItems.map(item => (
                  <div key={item.id} className="flex items-center pb-6 border-b border-gray-50 last:border-0 last:pb-0">
                    <img src={item.image} alt={item.name} className="w-20 h-20 sm:w-24 sm:h-24 rounded-2xl object-cover shadow-sm" />
                    <div className="ml-4 sm:ml-6 flex-1">
                      <h4 className="font-bold text-gray-800 text-lg">{item.name}</h4>
                      <p className="text-orange-600 font-bold">₹{item.price}</p>
                    </div>
                    <div className="flex items-center space-x-4 bg-gray-50 rounded-2xl p-2 sm:px-4">
                      <button 
                        onClick={() => onRemove(item.id)}
                        className="w-8 h-8 sm:w-10 sm:h-10 bg-white text-gray-400 rounded-xl flex items-center justify-center shadow-sm border border-gray-100 hover:text-red-500 transition-colors"
                      >
                        <i className="fas fa-minus text-xs"></i>
                      </button>
                      <span className="font-bold text-gray-700 w-6 text-center text-lg">{item.quantity}</span>
                      <button 
                        onClick={() => onAdd(item)}
                        className="w-8 h-8 sm:w-10 sm:h-10 bg-orange-500 text-white rounded-xl flex items-center justify-center shadow-md hover:bg-orange-600 transition-colors"
                      >
                        <i className="fas fa-plus text-xs"></i>
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>

          {/* Right Column: Order Summary */}
          <div className="lg:col-span-1">
            <div className="bg-white rounded-3xl p-8 shadow-xl border border-gray-50 sticky top-4">
              <h4 className="font-bold text-gray-800 text-xl mb-6">Order Summary</h4>
              <div className="space-y-4 mb-8">
                <div className="flex justify-between text-gray-500 font-medium">
                  <span>Subtotal</span>
                  <span className="text-gray-800">₹{subtotal}</span>
                </div>
                <div className="flex justify-between text-gray-500 font-medium">
                  <span>Delivery Fee</span>
                  <span className="text-gray-800">₹{deliveryFee}</span>
                </div>
                <div className="flex justify-between text-gray-500 font-medium">
                  <span>Tax & Packaging</span>
                  <span className="text-gray-800">₹0</span>
                </div>
                <div className="h-px bg-gray-100 w-full my-2"></div>
                <div className="flex justify-between text-2xl font-extrabold text-gray-800">
                  <span>Total</span>
                  <span className="text-orange-600">₹{total}</span>
                </div>
              </div>

              <div className="bg-orange-50 rounded-2xl p-4 mb-6 flex items-center">
                <i className="fas fa-ticket-simple text-orange-500 mr-3 text-lg"></i>
                <div className="flex-1">
                  <p className="text-xs font-bold text-orange-600 uppercase">Promo Code Applied</p>
                  <p className="text-[10px] text-orange-400">WELCOME20 applied at kitchen</p>
                </div>
              </div>

              <button 
                onClick={handlePlaceOrder}
                className="w-full bg-orange-500 text-white py-5 rounded-2xl font-bold text-xl shadow-xl shadow-orange-100 hover:bg-orange-600 active:scale-95 transition-all flex items-center justify-center"
              >
                <span>Complete Order</span>
                <i className="fas fa-arrow-right ml-3 text-sm opacity-50"></i>
              </button>

              <p className="text-center text-[10px] text-gray-400 mt-6 uppercase tracking-widest font-bold">Secure Payment via Hotel Anandam Pay</p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default OrderTab;

