          {activeTab === 'home' && (
            <HomeTab 
              items={items} 
              onAdd={addToCart} 
              onInstall={handleInstall}
              isInstalled={isInstalled}
            />
          )}
          {activeTab === 'order' && (
            <OrderTab 
              cartItems={cart} 
              onAdd={addToCart} 
              onRemove={removeFromCart}
              onClear={clearCart}
              onPlaced={() => setActiveTab('order')}
            />
          )}
          {activeTab === 'profile' && (
            <ProfileTab user={MOCK_USER} />
          )}
        </div>
      </main>

      {/* Notification Toast */}
      {showNotification && (
        <div className="fixed bottom-24 left-1/2 -translate-x-1/2 bg-gray-900 text-white px-6 py-3 rounded-2xl text-xs sm:text-sm shadow-2xl z-50 animate-bounce flex items-center whitespace-nowrap">
