import ProfileTab from './components/ProfileTab';
import BottomNav from './components/BottomNav';
import { supabase } from './supabase';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>('home');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isInstalled, setIsInstalled] = useState(false);
  const [showNotification, setShowNotification] = useState<string | null>(null);
  const [items, setItems] = useState<FoodItem[]>(FOOD_ITEMS);
  const [orderStatus, setOrderStatus] = useState<'idle' | 'processing' | 'success'>('idle');

  useEffect(() => {
    const fetchItems = async () => {
      try {
        const { data } = await supabase.from('food_items').select('*');
        if (data && data.length > 0) {
          setItems(data);
        }
      } catch (err) {
        console.debug('Supabase table not found, using defaults');
      }
    };
    fetchItems();
  }, []);

  const addToCart = (item: FoodItem) => {
    // If an order was just successful, clear it when adding new items
    if (orderStatus === 'success') {
      setOrderStatus('idle');
    }

    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      }
      return [...prev, { ...item, quantity: 1 }];
    });
    triggerNotification(`${item.name} added to cart!`);
  };

  const removeFromCart = (itemId: string) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === itemId);
      if (existing && existing.quantity > 1) {
        return prev.map(i => i.id === itemId ? { ...i, quantity: i.quantity - 1 } : i);
      }
      return prev.filter(i => i.id !== itemId);
    });
  };

  const clearCart = () => setCart([]);

  const triggerNotification = (msg: string) => {
    setShowNotification(msg);
    setTimeout(() => setShowNotification(null), 3000);
  };

  const handleInstall = () => {
    setIsInstalled(true);
    triggerNotification("Hotel Anandam installed successfully!");
  };

  const handlePlaceOrder = () => {
    if (cart.length === 0) return;
    setOrderStatus('processing');
    setTimeout(() => {
      setOrderStatus('success');
      setCart([]); // Clear cart after success
    }, 2000);
  };

  return (
    <div className="flex flex-col h-screen w-full bg-white overflow-hidden relative font-sans">

      {/* Header */}
      <header className="bg-orange-500 text-white shadow-md z-40 w-full shrink-0">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex items-center justify-between">
          <div className="flex flex-col">
            <h1 className="text-xl sm:text-2xl font-bold tracking-tight">Hotel Anandam</h1>
            <p className="text-[10px] sm:text-xs text-orange-100 flex items-center">
              <i className="fas fa-map-marker-alt mr-1"></i> Madurai, Tamil Nadu
            </p>
          </div>
          {!isInstalled && (
            <button 
              onClick={handleInstall}
              className="bg-white text-orange-500 px-4 py-2 rounded-full text-xs sm:text-sm font-bold shadow-sm hover:bg-orange-50 transition-colors"
            >
              <i className="fas fa-download mr-1"></i> <span className="hidden sm:inline">Install App</span><span className="inline sm:hidden">Install</span>
            </button>
          )}
        </div>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto custom-scrollbar bg-gray-50 pb-24 md:pb-28">
        <div className="max-w-7xl mx-auto w-full tab-content">
          {activeTab === 'home' && (
            <HomeTab 
              items={items} 
              onAdd={addToCart} 
              onInstall={handleInstall}
              isInstalled={isInstalled}
            />
          )}
          {activeTab === 'order' && (
            <OrderTab 
              cartItems={cart} 
              onAdd={addToCart} 
              onRemove={removeFromCart}
              onClear={clearCart}
              orderStatus={orderStatus}
              onPlaceOrder={handlePlaceOrder}
              onTrackOrder={() => setOrderStatus('idle')}
            />
          )}
          {activeTab === 'profile' && (
            <ProfileTab user={MOCK_USER} />
          )}
        </div>
      </main>

      {/* Notification Toast */}
      {showNotification && (
        <div className="fixed bottom-24 left-1/2 -translate-x-1/2 bg-gray-900 text-white px-6 py-3 rounded-2xl text-xs sm:text-sm shadow-2xl z-50 flex items-center whitespace-nowrap">
          <i className="fas fa-check-circle mr-2 text-green-400"></i>
          {showNotification}
        </div>
      )}

      {/* Bottom Navigation */}
      <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-100 z-30 shadow-[0_-4px_10px_rgba(0,0,0,0.05)] rounded-t-3xl md:rounded-none shrink-0">
        <div className="max-w-7xl mx-auto">
          <BottomNav 
            activeTab={activeTab} 
            setActiveTab={setActiveTab} 
            cartCount={cart.reduce((acc, curr) => acc + curr.quantity, 0)}
          />
        </div>
      </div>
    </div>
  );
};

