  const [menuItems, setMenuItems] = useState<FoodItem[]>(FOOD_ITEMS);

  useEffect(() => {
    const fetchMenu = async () => {
      try {
        const { data, error } = await supabase
          .from('food_items')
          .select('*');

        if (data && data.length > 0) {
          setMenuItems(data);
        } else if (error) {
          console.error('Error fetching from Supabase:', error);
        }
      } catch (err) {
        console.log('Using local fallback data');
      }
    };

    fetchMenu();
  }, []);

  const addToCart = (item: FoodItem) => {
    if (orderState === 'placed') setOrderState('idle');
    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      }
      return [...prev, { ...item, quantity: 1 }];
    });
    triggerNotification(`${item.name} added to basket`);
  };

  const removeFromCart = (itemId: string) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === itemId);
      if (existing && existing.quantity > 1) {
        return prev.map(i => i.id === itemId ? { ...i, quantity: i.quantity - 1 } : i);
      }
      return prev.filter(i => i.id !== itemId);
    });
  };

  const clearCart = () => setCart([]);

  const triggerNotification = (msg: string) => {
    setShowNotification(msg);
    setTimeout(() => setShowNotification(null), 2500);
  };

  const handleInstall = () => {
    setIsInstalled(true);
    triggerNotification("Hotel Anandam installed successfully!");
  };

  const handleOrderComplete = () => {
    setOrderState('placed');
    setCart([]);
  };

  return (
    <div className="flex flex-col h-screen w-full bg-white overflow-hidden relative">
      {/* Header */}
      <header className="bg-orange-500 text-white shadow-lg z-40 w-full shrink-0">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 py-4 flex items-center justify-between">
          <div className="flex flex-col">
            <h1 className="text-xl sm:text-2xl font-black tracking-tight italic">ANANDAM</h1>
            <div className="flex items-center text-[10px] sm:text-xs text-orange-100 font-medium">
              <i className="fas fa-location-dot mr-1"></i> Madurai, TN
            </div>
          </div>
          {!isInstalled && (
            <button 
              onClick={handleInstall}
              className="bg-white/20 backdrop-blur-md border border-white/30 text-white px-5 py-2 rounded-2xl text-xs sm:text-sm font-bold shadow-sm hover:bg-white hover:text-orange-500 transition-all active:scale-95"
            >
              <i className="fas fa-plus-circle mr-1.5"></i> Install
            </button>
          )}
        </div>
      </header>

      {/* Content */}
      <main className="flex-1 overflow-y-auto custom-scrollbar bg-slate-50 pb-28">
        <div className="max-w-7xl mx-auto w-full tab-content">
          {activeTab === 'home' && (
            <HomeTab 
              items={menuItems} 
              onAdd={addToCart} 
              onInstall={handleInstall}
              isInstalled={isInstalled}
            />
          )}
          {activeTab === 'order' && (
            <OrderTab 
              cartItems={cart} 
              onAdd={addToCart} 
              onRemove={removeFromCart}
              onClear={clearCart}
              onPlaced={handleOrderComplete}
              isPlaced={orderState === 'placed'}
            />
          )}
          {activeTab === 'profile' && (
            <ProfileTab user={MOCK_USER} />
          )}
        </div>
      </main>

      {/* Notifications */}
      {showNotification && (
        <div className="fixed bottom-24 left-1/2 -translate-x-1/2 bg-gray-900/90 backdrop-blur-md text-white px-6 py-3 rounded-2xl text-xs sm:text-sm shadow-2xl z-50 flex items-center space-x-3 border border-white/10">
          <div className="w-5 h-5 bg-green-500 rounded-full flex items-center justify-center">
            <i className="fas fa-check text-[10px]"></i>
          </div>
          <span className="font-bold">{showNotification}</span>
        </div>
