      {/* Navigation */}
      <div className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-xl border-t border-gray-100 z-30 shadow-[0_-10px_30px_rgba(0,0,0,0.03)] rounded-t-[2.5rem] md:rounded-none">
        <div className="max-w-7xl mx-auto">
