import React, { useState, useEffect } from 'react';
import { AppTab, CartItem, FoodItem } from './types';
import { FOOD_ITEMS } from './constants';
import HomeTab from './components/HomeTab';
import OrderTab from './components/OrderTab';
import ProfileTab from './components/ProfileTab';
import BottomNav from './components/BottomNav';
import LandingPage from './components/LandingPage';
import { supabase } from './supabase';
import { Session } from '@supabase/supabase-js';

const App: React.FC = () => {
  const [session, setSession] = useState<Session | null>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<AppTab>('home');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [showNotification, setShowNotification] = useState<string | null>(null);
  const [items, setItems] = useState<FoodItem[]>(FOOD_ITEMS);
  const [orderStatus, setOrderStatus] = useState<'idle' | 'processing' | 'success'>('idle');

  const cartTotalItems = cart.reduce((acc, curr) => acc + curr.quantity, 0);

  useEffect(() => {
    // Check initial session
    const initAuth = async () => {
      const { data: { session } } = await supabase.auth.getSession();
      setSession(session);
      setAuthLoading(false);
    };

    initAuth();

    // Listen for changes
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      setAuthLoading(false);
    });

    return () => subscription.unsubscribe();
  }, []);

  useEffect(() => {
    const fetchItems = async () => {
      try {
        const { data } = await supabase.from('food_items').select('*');
        if (data && data.length > 0) {
          setItems(data);
        }
      } catch (err) {
        console.debug('Supabase table not found or empty, using defaults');
      }
    };
    if (session) fetchItems();
  }, [session]);

  const addToCart = (item: FoodItem) => {
    if (orderStatus === 'success') {
      setOrderStatus('idle');
    }

    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      }
      return [...prev, { ...item, quantity: 1 }];
    });
    triggerNotification(`${item.name} added to cart!`);
  };

  const removeFromCart = (itemId: string) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === itemId);
      if (existing && existing.quantity > 1) {
        return prev.map(i => i.id === itemId ? { ...i, quantity: i.quantity - 1 } : i);
      }
      return prev.filter(i => i.id !== itemId);
    });
  };

  const clearCart = () => setCart([]);

  const triggerNotification = (msg: string) => {
    setShowNotification(msg);
    setTimeout(() => setShowNotification(null), 3000);
  };

  const handlePlaceOrder = async () => {
    if (cart.length === 0 || !session?.user) return;
    setOrderStatus('processing');

    const subtotal = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    const deliveryFee = 30;
    const total = subtotal + deliveryFee;

    try {
      const { error } = await supabase.from('orders').insert([{
        user_email: session.user.email,
        items: cart,
        total_amount: total,
        status: 'Completed'
      }]);

      if (error) throw error;

      setTimeout(() => {
        setOrderStatus('success');
        setCart([]);
      }, 1500);
    } catch (err) {
      console.error('Failed to save order:', err);
      triggerNotification("Failed to place order. Try again.");
      setOrderStatus('idle');
    }
  };

  if (authLoading) {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-white">
        <div className="w-12 h-12 border-4 border-orange-500 border-t-transparent rounded-full animate-spin mb-4"></div>
        <p className="text-gray-400 font-medium animate-pulse">Welcome to Anandam...</p>
      </div>
    );
  }

  if (!session) {
    return <LandingPage />;
  }

  return (
    <div className="flex flex-col h-screen w-full bg-white overflow-hidden relative font-sans">

      {/* Header */}
      <header className="bg-orange-500 text-white shadow-md z-40 w-full shrink-0">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex items-center justify-between">
          <div className="flex flex-col cursor-pointer" onClick={() => setActiveTab('home')}>
            <h1 className="text-xl sm:text-2xl font-bold tracking-tight">Hotel Anandam</h1>
            <p className="text-[10px] sm:text-xs text-orange-100 flex items-center">
              <i className="fas fa-map-marker-alt mr-1"></i> Madurai, Tamil Nadu
            </p>
          </div>

          <button 
            onClick={() => setActiveTab('order')}
            className="bg-white text-orange-600 px-4 py-2 rounded-full text-xs sm:text-sm font-bold shadow-md hover:bg-orange-50 transition-all flex items-center relative active:scale-95"
          >
            <i className="fas fa-shopping-basket mr-2"></i>
            <span>My Basket</span>
            {cartTotalItems > 0 && (
              <span className="ml-2 bg-orange-600 text-white w-5 h-5 rounded-full flex items-center justify-center text-[10px] animate-pulse">
                {cartTotalItems}
              </span>
            )}
          </button>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto custom-scrollbar bg-gray-50 pb-24 md:pb-28">
        <div className="max-w-7xl mx-auto w-full tab-content">
          {activeTab === 'home' && (
            <HomeTab 
              items={items} 
              onAdd={addToCart} 
            />
          )}
          {activeTab === 'order' && (
            <OrderTab 
              cartItems={cart} 
              onAdd={addToCart} 
              onRemove={removeFromCart}
              onClear={clearCart}
              orderStatus={orderStatus}
              onPlaceOrder={handlePlaceOrder}
              onTrackOrder={() => setActiveTab('profile')}
            />
          )}
          {activeTab === 'profile' && (
            <ProfileTab />
          )}
        </div>
      </main>

      {/* Notification Toast */}
      {showNotification && (
        <div className="fixed bottom-24 left-1/2 -translate-x-1/2 bg-gray-900 text-white px-6 py-3 rounded-2xl text-xs sm:text-sm shadow-2xl z-50 flex items-center whitespace-nowrap">
          <i className="fas fa-check-circle mr-2 text-green-400"></i>
          {showNotification}
        </div>
      )}

      {/* Bottom Navigation */}
      <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-100 z-30 shadow-[0_-4px_10px_rgba(0,0,0,0.05)] rounded-t-3xl md:rounded-none shrink-0">
        <div className="max-w-7xl mx-auto">
          <BottomNav 
            activeTab={activeTab} 
            setActiveTab={setActiveTab} 
            cartCount={cartTotalItems}
          />
        </div>
      </div>
    </div>
  );
};

export default App;

