                  >
                    {isSignUp ? 'Sign In' : 'Register now'}
                  </button>
                </p>
              </div>
            </>
          )}

          {message?.type === 'error' && (
            <div className={`mt-6 p-4 rounded-xl text-xs font-medium text-center border animate-in slide-in-from-bottom-2 ${
              message.text.includes('Too many') || message.text.includes('verified') ? 'bg-orange-50 text-orange-600 border-orange-100' : 'bg-red-50 text-red-600 border-red-100'
            }`}>
              <i className={`fas ${message.text.includes('Too many') ? 'fa-clock' : 'fa-exclamation-circle'} mr-2`}></i>
              {message.text}
