const LandingPage: React.FC = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [isSignUp, setIsSignUp] = useState(false);
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState<{ type: 'success' | 'error', text: string } | null>(null);

  const handleGoogleSignIn = async () => {
    try {
      const { error } = await supabase.auth.signInWithOAuth({
        provider: 'google',
        options: {
          redirectTo: window.location.origin
        }
      });
      if (error) throw error;
    } catch (error: any) {
      setMessage({ type: 'error', text: error.message });
    }
  };

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    if (loading) return;

    // Simple validation
    if (!email || !password || (isSignUp && !fullName)) {
      setMessage({ type: 'error', text: 'Please fill in all fields.' });
      return;
    }

    setLoading(true);
    setMessage(null);

    try {
      if (isSignUp) {
        // Sign Up Flow
        const { error, data } = await supabase.auth.signUp({
          email,
          password,
          options: {
            data: {
              full_name: fullName,
              avatar_url: `https://i.pravatar.cc/150?u=${email}`
            }
          }
        });

        if (error) {
          if (error.status === 429) {
            throw new Error('Rate limit exceeded. Please wait a few minutes before trying again.');
          }
          throw error;
        }

        if (data.user) {
          // If session is null, it means email confirmation is required
          if (!data.session) {
            setMessage({ 
              type: 'success', 
              text: 'Account created! Check your email for a confirmation link to activate your account.' 
            });
            // Clear inputs for security
            setEmail('');
            setPassword('');
            setFullName('');
          } else {
            setMessage({ type: 'success', text: 'Registration successful! Logging you in...' });
          }
        }
      } else {
        // Login Flow
        const { error, data } = await supabase.auth.signInWithPassword({
          email,
          password,
        });

        if (error) {
          if (error.message.includes('confirm your email')) {
            throw new Error('Email not confirmed. Please check your inbox for the activation link.');
          }
          if (error.status === 429) {
            throw new Error('Too many attempts. Please try again later.');
          }
          throw error;
        }

        if (data.user) {
          setMessage({ type: 'success', text: 'Success! Welcome back.' });
        }
      }
    } catch (error: any) {
      console.error('Auth Error:', error);
      setMessage({ type: 'error', text: error.message || 'An unexpected error occurred.' });
    } finally {
      setLoading(false);
