            throw new Error('Your email is not confirmed yet. Check your inbox for the link we sent earlier.');
          }
          if (error.status === 429) {
            throw new Error('Too many attempts. Please try again in 5-10 minutes.');
          }
          throw error;
        }

        if (data.user) {
          setMessage({ type: 'success', text: 'Welcome back to Hotel Anandam!' });
        }
      }
