import React, { useState, useEffect, useRef } from 'react';
import { Order } from '../types';
import { supabase } from '../supabase';
import { User } from '@supabase/supabase-js';

const ProfileTab: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [showHistory, setShowHistory] = useState(false);
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(false);
  const [uploading, setUploading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    supabase.auth.getUser().then(({ data: { user } }) => {
      setUser(user);
    });
  }, []);

  useEffect(() => {
    if (showHistory && user?.email) {
      fetchOrderHistory();
    }
  }, [showHistory, user]);

  const fetchOrderHistory = async () => {
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('orders')
        .select('*')
        .eq('user_email', user?.email)
        .order('created_at', { ascending: false });

      if (error) throw error;
      setOrders(data || []);
    } catch (err) {
      console.error('Error fetching history:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
  };

  const handleAvatarUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    try {
      if (!event.target.files || event.target.files.length === 0) return;
      if (!user) return;

      setUploading(true);
      const file = event.target.files[0];
      const fileExt = file.name.split('.').pop();
      const fileName = `${user.id}/${Date.now()}.${fileExt}`;

      // Upload to Supabase Storage
      const { error: uploadError } = await supabase.storage
        .from('avatars')
        .upload(fileName, file, { upsert: true });

      if (uploadError) throw uploadError;

      // Get Public URL
      const { data: { publicUrl } } = supabase.storage
        .from('avatars')
        .getPublicUrl(fileName);

      // Update Auth User Metadata
      const { error: updateError } = await supabase.auth.updateUser({
        data: { avatar_url: publicUrl }
      });

      if (updateError) throw updateError;

      // Update Profile Table
      await supabase.from('profiles').upsert({
        id: user.id,
        avatar_url: publicUrl,
        updated_at: new Date().toISOString(),
      });

      // Update Local State
      setUser(prev => prev ? {
        ...prev,
        user_metadata: {
          ...prev.user_metadata,
          avatar_url: publicUrl
        }
      } : null);

    } catch (error: any) {
      console.error('Error uploading avatar:', error);
      alert('Failed to upload image. Please ensure "avatars" storage bucket exists and is public.');
    } finally {
      setUploading(false);
    }
  };

  if (!user) return null;

  if (showHistory) {
    return (
      <div className="p-4 sm:p-8 lg:p-12 max-w-4xl mx-auto animate-in fade-in slide-in-from-right-4 duration-300">
        <div className="flex items-center space-x-4 mb-8">
          <button 
            onClick={() => setShowHistory(false)}
            className="w-10 h-10 rounded-full bg-white border border-gray-100 flex items-center justify-center text-gray-400 hover:text-orange-500 hover:border-orange-100 transition-all shadow-sm"
          >
            <i className="fas fa-arrow-left"></i>
          </button>
          <h3 className="text-2xl font-extrabold text-gray-800">Order History</h3>
        </div>

        {loading ? (
          <div className="flex flex-col items-center justify-center py-20">
            <div className="w-10 h-10 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div>
            <p className="text-gray-400 mt-4 font-medium">Fetching your delicious history...</p>
          </div>
        ) : orders.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-20 bg-white rounded-3xl border border-dashed border-gray-100">
            <i className="fas fa-history text-4xl text-gray-200 mb-4"></i>
            <p className="text-gray-500 font-bold">No orders found</p>
            <p className="text-gray-400 text-sm mt-1">Start ordering to build your history!</p>
          </div>
        ) : (
          <div className="space-y-4">
            {orders.map((order) => (
              <div key={order.id} className="bg-white rounded-2xl p-6 border border-gray-50 shadow-sm hover:shadow-md transition-shadow">
                <div className="flex justify-between items-start mb-4">
                  <div>
                    <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">Order ID: {order.id.slice(0, 8)}</p>
                    <p className="text-gray-500 text-xs mt-1">{new Date(order.created_at).toLocaleDateString(undefined, { 
                      year: 'numeric', month: 'long', day: 'numeric', hour: '2-digit', minute: '2-digit' 
                    })}</p>
                  </div>
                  <span className="bg-green-50 text-green-600 text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-widest">
                    {order.status}
                  </span>
                </div>

                <div className="border-t border-gray-50 pt-4 mt-4">
                  <div className="space-y-2">
                    {order.items.map((item, idx) => (
                      <div key={idx} className="flex justify-between text-sm">
                        <span className="text-gray-600">
                          <span className="font-bold text-gray-800">{item.quantity}x</span> {item.name}
                        </span>
                        <span className="text-gray-400">₹{item.price * item.quantity}</span>
                      </div>
                    ))}
                  </div>
                  <div className="flex justify-between items-center mt-4 pt-4 border-t border-gray-50">
                    <span className="text-gray-800 font-bold">Total Paid</span>
                    <span className="text-orange-600 font-black text-lg">₹{order.total_amount}</span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="p-4 sm:p-8 lg:p-12 max-w-4xl mx-auto">
      <div className="flex flex-col items-center text-center mb-12 sm:mb-16">
        <div className="relative inline-block">
          <div className="w-28 h-28 sm:w-40 sm:h-40 rounded-full border-4 border-orange-50 p-1.5 mb-6 relative z-10 overflow-hidden shadow-lg group">
            <img 
              src={user.user_metadata?.avatar_url || `https://i.pravatar.cc/150?u=${user.id}`} 
              alt={user.user_metadata?.full_name || 'User'} 
              className="w-full h-full rounded-full object-cover group-hover:scale-110 transition-transform duration-500" 
            />
          </div>
          <div className="absolute inset-0 bg-orange-200 rounded-full blur-2xl opacity-20 pointer-events-none"></div>

          <button 
            onClick={() => fileInputRef.current?.click()}
            disabled={uploading}
            className="absolute bottom-6 right-0 sm:bottom-8 sm:right-2 bg-orange-500 text-white w-8 h-8 sm:w-10 sm:h-10 rounded-full flex items-center justify-center shadow-lg border-4 border-white hover:bg-orange-600 transition-all z-20 active:scale-90"
            title="Update Profile Picture"
          >
            {uploading ? (
              <i className="fas fa-spinner animate-spin text-xs"></i>
            ) : (
              <i className="fas fa-plus text-sm"></i>
            )}
          </button>
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleAvatarUpload}
            className="hidden" 
            accept="image/*"
          />
        </div>
        <h3 className="text-3xl sm:text-4xl font-extrabold text-gray-800 mb-1">{user.user_metadata?.full_name || user.email?.split('@')[0]}</h3>
        <p className="text-gray-500 font-medium">{user.email}</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="space-y-8">
          <div>
            <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4 ml-1">Delivery Destination</h4>
            <div className="bg-white rounded-3xl p-6 border border-gray-100 shadow-sm flex items-start group hover:border-orange-200 transition-colors">
              <div className="w-12 h-12 bg-orange-50 text-orange-500 rounded-2xl flex items-center justify-center flex-shrink-0 group-hover:bg-orange-500 group-hover:text-white transition-all">
                <i className="fas fa-location-dot text-lg"></i>
              </div>
              <div className="ml-5">
                <p className="font-bold text-gray-800 text-lg">Home Address</p>
                <p className="text-gray-500 text-sm leading-relaxed mt-1">
                  {user.user_metadata?.address || 'Add your address to get started'}
                </p>
                <button className="text-orange-500 text-xs font-bold mt-3 hover:underline">Add Address</button>
              </div>
            </div>
          </div>

          <div>
            <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4 ml-1">Contact Details</h4>
            <div className="bg-white rounded-3xl p-6 border border-gray-100 shadow-sm flex items-center group hover:border-blue-200 transition-colors">
              <div className="w-12 h-12 bg-blue-50 text-blue-500 rounded-2xl flex items-center justify-center flex-shrink-0 group-hover:bg-blue-500 group-hover:text-white transition-all">
                <i className="fas fa-phone text-lg"></i>
              </div>
              <div className="ml-5">
                <p className="font-bold text-gray-800 text-lg">Phone</p>
                <p className="text-gray-500 font-medium">{user.phone || 'Not linked'}</p>
              </div>
            </div>
          </div>
        </div>

        <div className="space-y-8">
          <div>
            <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4 ml-1">Account Options</h4>
            <div className="flex flex-col space-y-4">
              <button 
                onClick={() => setShowHistory(true)}
                className="w-full py-5 bg-white border border-gray-100 text-gray-700 rounded-2xl font-bold text-sm hover:bg-gray-50 transition-colors flex items-center justify-center space-x-3 shadow-sm active:scale-[0.98]"
              >
                <i className="fas fa-clock-rotate-left"></i>
                <span>Order History</span>
              </button>
              <button 
                onClick={handleLogout}
                className="w-full py-5 border-2 border-red-50 text-red-500 rounded-2xl font-bold text-sm hover:bg-red-50 transition-colors flex items-center justify-center space-x-3"
              >
                <i className="fas fa-sign-out-alt"></i>
                <span>Logout Securely</span>
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

