import React, { useState, useEffect, useRef } from 'react';
import { Order } from '../types';
import { supabase } from '../supabase';
import { User } from '@supabase/supabase-js';

interface ProfileTabProps {
  user: User;
}

const ProfileTab: React.FC<ProfileTabProps> = ({ user }) => {
  const [showHistory, setShowHistory] = useState(false);
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(false);
  const [uploading, setUploading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (showHistory && user?.email) {
      fetchOrderHistory();
    }
  }, [showHistory, user]);

  const fetchOrderHistory = async () => {
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('orders')
        .select('*')
        .eq('user_email', user?.email)
        .order('created_at', { ascending: false });

      if (error) throw error;
      setOrders(data || []);
    } catch (err) {
      console.error('Error fetching history:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
  };

  const resizeImage = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const img = new Image();
      img.src = URL.createObjectURL(file);
      img.onload = () => {
        const canvas = document.createElement('canvas');
        const MAX_WIDTH = 300;
        const MAX_HEIGHT = 300;
        let width = img.width;
        let height = img.height;

        if (width > height) {
          if (width > MAX_WIDTH) {
            height *= MAX_WIDTH / width;
            width = MAX_WIDTH;
          }
        } else {
          if (height > MAX_HEIGHT) {
            width *= MAX_HEIGHT / height;
            height = MAX_HEIGHT;
          }
        }
        canvas.width = width;
        canvas.height = height;
        const ctx = canvas.getContext('2d');
        if (ctx) {
          ctx.drawImage(img, 0, 0, width, height);
          resolve(canvas.toDataURL('image/jpeg', 0.7));
        } else {
          reject(new Error('Canvas context missing'));
        }
      };
      img.onerror = (error) => reject(error);
    });
  };

  const handleAvatarUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    try {
      if (!event.target.files || event.target.files.length === 0) return;
      if (!user) return;

      setUploading(true);
      const file = event.target.files[0];

      // 1. Resize image to ensure it's lightweight (approx 300x300)
      // This is crucial for the fallback mechanism (saving as Base64 in DB)
      const base64Image = await resizeImage(file);

      let finalAvatarUrl = base64Image;
      let storageUploadSuccess = false;

      // 2. Try uploading to Supabase Storage 'avatars' bucket
      try {
        const fileExt = 'jpg'; // We converted to jpeg in resizeImage
        const fileName = `${user.id}/${Date.now()}.${fileExt}`;

        // Convert Base64 back to Blob for storage upload
        const res = await fetch(base64Image);
        const blob = await res.blob();

        const { error: uploadError } = await supabase.storage
          .from('avatars')
          .upload(fileName, blob, { upsert: true, contentType: 'image/jpeg' });

        if (!uploadError) {
          const { data } = supabase.storage.from('avatars').getPublicUrl(fileName);
          finalAvatarUrl = data.publicUrl;
          storageUploadSuccess = true;
        } else {
          console.warn('Supabase Storage upload failed (likely missing bucket), falling back to Base64 storage.', uploadError.message);
        }
      } catch (storageErr) {
        console.warn('Storage operation failed, falling back to Base64:', storageErr);
      }

      // 3. Update User Metadata & Profile Table
      // If storage failed, we use the Base64 string directly.

      const { error: updateError } = await supabase.auth.updateUser({
        data: { avatar_url: finalAvatarUrl }
      });

      if (updateError) throw updateError;

      await supabase.from('profiles').upsert({
        id: user.id,
        avatar_url: finalAvatarUrl,
        updated_at: new Date().toISOString(),
      });

      if (!storageUploadSuccess) {
        // Optional: Inform user it worked but might be limited
        console.log('Avatar updated using local storage fallback.');
      }

    } catch (error: any) {
      console.error('Error uploading avatar:', error);
      alert('Failed to update image. Please check your connection and try again.');
    } finally {
      setUploading(false);
      // Reset file input so selecting the same file works again if needed
      if (fileInputRef.current) {
        fileInputRef.current.value = '';
      }
    }
  };

  if (!user) return null;

  if (showHistory) {
    return (
      <div className="p-4 sm:p-8 lg:p-12 max-w-4xl mx-auto animate-in fade-in slide-in-from-right-4 duration-300">
