import React, { useState } from 'react';
import { CartItem, FoodItem } from '../types';

interface OrderTabProps {
  cartItems: CartItem[];
  onAdd: (item: FoodItem) => void;
  onRemove: (itemId: string) => void;
  onClear: () => void;
  orderStatus: 'idle' | 'processing' | 'success';
  onPlaceOrder: (phone: string, location: string) => void;
  onTrackOrder: () => void;
}

const OrderTab: React.FC<OrderTabProps> = ({ 
  cartItems, 
  onAdd, 
  onRemove, 
  onClear, 
  orderStatus, 
  onPlaceOrder,
  onTrackOrder 
}) => {
  const [phone, setPhone] = useState('');
  const [location, setLocation] = useState('S-block');
  const [error, setError] = useState<string | null>(null);

  const subtotal = cartItems.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const deliveryFee = subtotal > 0 ? 30 : 0;
  const total = subtotal + deliveryFee;

  const handleValidateAndOrder = () => {
    if (phone.length !== 10 || !/^\d+$/.test(phone)) {
      setError('Please enter a valid 10-digit mobile number');
      return;
    }
    setError(null);
    onPlaceOrder(phone, location);
  };

  if (orderStatus === 'processing') {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] p-6 text-center">
        <div className="w-20 h-20 border-4 border-orange-500 border-t-transparent rounded-full animate-spin mb-6"></div>
        <h3 className="text-2xl font-bold text-gray-800">Sending to Kitchen</h3>
        <p className="text-gray-500 mt-2 text-sm">Hotel Anandam is preparing your feast...</p>
      </div>
    );
