import React, { useState, useEffect, useRef } from 'react';
import { Order } from '../types';
import { supabase } from '../supabase';
import { User } from '@supabase/supabase-js';

interface ProfileTabProps {
  user: User;
  onOpenAdmin?: () => void;
}

const ProfileTab: React.FC<ProfileTabProps> = ({ user, onOpenAdmin }) => {
  const [showHistory, setShowHistory] = useState(false);
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    let subscription: any;
    if (showHistory && user?.email) {
      fetchOrderHistory();
      subscription = supabase
        .channel('user-orders-channel')
        .on('postgres_changes', { event: 'UPDATE', schema: 'public', table: 'orders', filter: `user_email=eq.${user.email}` }, fetchOrderHistory)
        .subscribe();
    }
    return () => {
      if (subscription) subscription.unsubscribe();
    };
  }, [showHistory, user]);

  const fetchOrderHistory = async () => {
    if (!user?.email) return;
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('orders')
        .select('*')
        .eq('user_email', user.email)
        .order('created_at', { ascending: false });

      if (error) throw error;
      setOrders(data || []);
    } catch (err) {
      console.error('Error fetching history:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
  };

  if (!user) return null;

  if (showHistory) {
    return (
      <div className="p-4 sm:p-8 lg:p-12 max-w-4xl mx-auto animate-in fade-in slide-in-from-right-4 duration-300">
        <div className="flex items-center space-x-4 mb-8">
          <button 
            onClick={() => setShowHistory(false)}
            className="w-10 h-10 rounded-full bg-white border border-gray-100 flex items-center justify-center text-gray-400 hover:text-orange-500 transition-all shadow-sm"
          >
            <i className="fas fa-arrow-left"></i>
          </button>
          <h3 className="text-2xl font-extrabold text-gray-800">Order Tracking</h3>
        </div>

        {loading && orders.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-20">
            <div className="w-10 h-10 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div>
            <p className="text-gray-400 mt-4 font-medium italic text-sm">Loading your orders...</p>
          </div>
        ) : orders.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-20 bg-white rounded-3xl border border-dashed border-gray-100">
            <i className="fas fa-history text-4xl text-gray-200 mb-4"></i>
            <p className="text-gray-500 font-bold">No orders yet</p>
          </div>
        ) : (
          <div className="space-y-6">
            {orders.map((order) => (
              <div key={order.id} className="bg-white rounded-3xl p-6 border border-gray-50 shadow-sm relative overflow-hidden">
                <div className="flex justify-between items-start mb-6">
                  <div>
                    <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-widest ${
                      order.status === 'Pending Acceptance' ? 'bg-amber-100 text-amber-600' :
                      order.status === 'Preparing' ? 'bg-blue-100 text-blue-600' :
                      order.status === 'Ready' ? 'bg-green-100 text-green-600' : 'bg-gray-100 text-gray-600'
                    }`}>
                      {order.status === 'Pending Acceptance' ? 'Waiting for Acceptance' : 
                       order.status === 'Preparing' ? 'Your order is Preparing' :
                       order.status === 'Ready' ? 'Order is Ready!' : order.status}
                    </span>
                    <p className="text-[10px] text-gray-400 font-bold uppercase mt-2">ID: {order.id.slice(0, 8)} • {new Date(order.created_at).toLocaleTimeString()}</p>
                  </div>
                  <p className="text-xl font-black text-orange-500">₹{order.total_amount}</p>
                </div>

                {/* Progress Visualizer */}
                <div className="flex items-center justify-between mb-8 px-4 relative">
                  <div className="absolute top-1/2 left-4 right-4 h-1 bg-gray-100 -translate-y-1/2 -z-10"></div>
                  <div className={`absolute top-1/2 left-4 h-1 bg-orange-500 -translate-y-1/2 -z-10 transition-all duration-1000`} style={{ 
                    width: order.status === 'Pending Acceptance' ? '0%' : 
                           order.status === 'Preparing' ? '50%' : '100%' 
                  }}></div>

                  {[
                    { s: 'Pending Acceptance', i: 'fa-hourglass-start' },
                    { s: 'Preparing', i: 'fa-fire-burner' },
                    { s: 'Ready', i: 'fa-check-circle' }
                  ].map((step, idx) => {
                    const isActive = order.status === step.s || 
                      (step.s === 'Pending Acceptance' && (order.status === 'Preparing' || order.status === 'Ready')) ||
                      (step.s === 'Preparing' && order.status === 'Ready');

                    return (
                      <div key={idx} className="flex flex-col items-center">
                        <div className={`w-10 h-10 rounded-full flex items-center justify-center border-4 transition-all ${
                          isActive ? 'bg-orange-500 border-white text-white shadow-lg' : 'bg-white border-gray-100 text-gray-300'
                        }`}>
                          <i className={`fas ${step.i} text-xs`}></i>
                        </div>
                      </div>
                    );
                  })}
                </div>

                <div className="bg-gray-50 rounded-2xl p-4 space-y-2">
                  {order.items.map((item, idx) => (
                    <div key={idx} className="flex justify-between text-xs">
                      <span className="text-gray-600 font-medium">{item.quantity}x {item.name}</span>
                      <span className="text-gray-400">₹{item.price * item.quantity}</span>
                    </div>
                  ))}
                  <div className="pt-2 border-t border-gray-200 mt-2 flex justify-between items-center">
                    <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Delivering to: {order.location}</span>
                    <span className="text-[10px] font-black text-blue-500 uppercase tracking-widest">{order.payment_method}</span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="p-4 sm:p-8 lg:p-12 max-w-4xl mx-auto">
      <div className="flex flex-col items-center text-center mb-12 sm:mb-16">
        <div className="relative inline-block mb-6">
          <div className="w-28 h-28 sm:w-36 sm:h-36 rounded-full border-4 border-orange-50 p-1 relative overflow-hidden shadow-lg">
            <img src={user.user_metadata?.avatar_url || `https://i.pravatar.cc/150?u=${user.id}`} alt="User" className="w-full h-full rounded-full object-cover" />
          </div>
        </div>
        <h3 className="text-3xl font-black text-gray-800 mb-1">{user.user_metadata?.full_name || user.email?.split('@')[0]}</h3>
        <p className="text-gray-500 font-medium text-sm">{user.email}</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="space-y-6">
          <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Order Tracking</h4>
          <button 
            onClick={() => setShowHistory(true)}
            className="w-full py-5 bg-white border border-gray-100 text-gray-700 rounded-3xl font-bold text-sm hover:bg-gray-50 flex items-center px-6 space-x-4 shadow-sm group transition-all"
          >
            <div className="w-12 h-12 bg-orange-50 text-orange-500 rounded-2xl flex items-center justify-center transition-transform group-hover:scale-110">
              <i className="fas fa-truck-fast"></i>
            </div>
            <div className="text-left">
              <span className="block font-black text-gray-900">Track Current Orders</span>
              <span className="text-[10px] text-gray-400 uppercase">View Status & History</span>
            </div>
          </button>

          <button 
            onClick={onOpenAdmin}
            className="w-full py-5 bg-gray-900 text-white rounded-3xl font-bold text-sm hover:bg-black flex items-center px-6 space-x-4 shadow-xl group transition-all"
          >
            <div className="w-12 h-12 bg-gray-800 text-orange-400 rounded-2xl flex items-center justify-center transition-transform group-hover:rotate-12">
              <i className="fas fa-utensils"></i>
            </div>
            <div className="text-left">
              <span className="block font-black">Kitchen Login</span>
              <span className="text-[10px] text-gray-500 uppercase">Restaurant Management</span>
            </div>
          </button>
        </div>

        <div className="space-y-6">
          <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Settings</h4>
          <button 
            onClick={handleLogout}
            className="w-full py-5 border-2 border-red-50 text-red-500 rounded-3xl font-bold text-sm hover:bg-red-50 flex items-center px-6 space-x-4 transition-all"
          >
            <div className="w-12 h-12 bg-red-100 text-red-600 rounded-2xl flex items-center justify-center"><i className="fas fa-power-off"></i></div>
            <span className="font-black">Logout</span>
          </button>
        </div>
      </div>
    </div>
  );
};

