                  {order.items.map((item, idx) => (
                    <div key={idx} className="flex justify-between items-center text-xs">
                      <span className="text-gray-600 font-medium"><span className="text-orange-500 font-black">{item.quantity}x</span> {item.name}</span>
                      <span className="text-gray-400">₹{item.price * item.quantity}</span>
                    </div>
                  ))}
                </div>

                <div className="mt-6 space-y-2">
                  {order.status === 'Pending Acceptance' && (
                    <button 
                      onClick={() => updateOrderStatus(order.id, 'Preparing')}
                      className="w-full bg-blue-600 text-white py-3.5 rounded-xl font-bold text-sm shadow-lg shadow-blue-50 active:scale-95 transition-all flex items-center justify-center"
                    >
                      <i className="fas fa-check-circle mr-2"></i>
