                  {order.status === 'Ready' && (
                    <button 
                      onClick={() => updateOrderStatus(order.id, 'Delivered')}
                      className="w-full bg-gray-900 text-white py-3.5 rounded-xl font-bold text-sm active:scale-95 transition-all flex items-center justify-center"
                    >
                      <i className="fas fa-truck mr-2"></i>
                      Mark as Delivered
                    </button>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {showProductForm && (
        <div className="fixed inset-0 bg-black/40 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] p-8 shadow-2xl animate-in zoom-in-95 duration-200">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-2xl font-black text-gray-900">Add to Menu</h3>
              <button onClick={() => setShowProductForm(false)} className="text-gray-400 hover:text-gray-600">
                <i className="fas fa-times text-xl"></i>
              </button>
            </div>
            <form onSubmit={handleAddProduct} className="space-y-4">
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1 mb-2">Item Name</label>
                <input type="text" required className="w-full px-5 py-3.5 bg-gray-50 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none font-bold text-gray-800" value={newProduct.name} onChange={e => setNewProduct({...newProduct, name: e.target.value})} />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1 mb-2">Price (₹)</label>
                  <input type="number" required className="w-full px-5 py-3.5 bg-gray-50 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none font-bold text-gray-800" value={newProduct.price} onChange={e => setNewProduct({...newProduct, price: parseInt(e.target.value)})} />
                </div>
                <div>
                  <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1 mb-2">Category</label>
                  <select className="w-full px-5 py-3.5 bg-gray-50 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none font-bold text-gray-800 appearance-none" value={newProduct.category} onChange={e => setNewProduct({...newProduct, category: e.target.value})}>
                    <option>Rice</option><option>Noodles</option><option>Breads</option><option>Specials</option><option>Drinks</option>
                  </select>
                </div>
              </div>

              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1 mb-2">Image URL</label>
                <input 
                  type="url" 
                  placeholder="https://example.com/image.jpg"
                  className="w-full px-5 py-3.5 bg-gray-50 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none font-bold text-gray-800" 
                  value={newProduct.image} 
                  onChange={e => setNewProduct({...newProduct, image: e.target.value})} 
                />
              </div>

              {newProduct.image && (
                <div className="mt-2 rounded-2xl overflow-hidden h-32 w-full border border-gray-100">
                  <img 
                    src={newProduct.image} 
                    alt="Preview" 
                    className="w-full h-full object-cover"
                    onError={(e) => {
                      (e.target as HTMLImageElement).src = 'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?auto=format&fit=crop&w=400&q=80';
                    }}
                  />
                </div>
              )}

              <button type="submit" className="w-full bg-orange-500 text-white py-4 rounded-2xl font-bold text-lg shadow-xl shadow-orange-100 mt-4 hover:bg-orange-600 transition-all">Create Product</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminTab;

import React, { useState, useEffect } from 'react';
import { AppTab, CartItem, FoodItem } from './types';
import { FOOD_ITEMS } from './constants';
import HomeTab from './components/HomeTab';
import OrderTab from './components/OrderTab';
import ProfileTab from './components/ProfileTab';
import AdminTab from './components/AdminTab';
import BottomNav from './components/BottomNav';
import LandingPage from './components/LandingPage';
import { supabase } from './supabase';
import { Session } from '@supabase/supabase-js';

const App: React.FC = () => {
  const [session, setSession] = useState<Session | null>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<AppTab>('home');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [showNotification, setShowNotification] = useState<string | null>(null);
  const [items, setItems] = useState<FoodItem[]>(FOOD_ITEMS);
  const [orderStatus, setOrderStatus] = useState<'idle' | 'processing' | 'success'>('idle');
  const [installPrompt, setInstallPrompt] = useState<any>(null);

  const [searchQuery, setSearchQuery] = useState('');
  const [isListening, setIsListening] = useState(false);

  const cartTotalItems = cart.reduce((acc, curr) => acc + curr.quantity, 0);

  useEffect(() => {
    const initAuth = async () => {
      try {
        const { data: { session } } = await supabase.auth.getSession();
        setSession(session);
      } catch (e) {
        console.error('Initial session fetch failed', e);
      } finally {
        setAuthLoading(false);
      }
    };

    initAuth();

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });

    const handleBeforeInstallPrompt = (e: Event) => {
      e.preventDefault();
      setInstallPrompt(e);
    };

    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);

    return () => {
      subscription.unsubscribe();
      window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    };
  }, []);

  const handleInstallClick = async () => {
    if (!installPrompt) return;
    installPrompt.prompt();
    const { outcome } = await installPrompt.userChoice;
    if (outcome === 'accepted') {
      setInstallPrompt(null);
    }
  };

  const addToCart = (item: FoodItem) => {
    if (!item.inStock) {
      triggerNotification(`${item.name} is currently out of stock!`);
      return;
    }
    if (orderStatus === 'success') setOrderStatus('idle');
    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      }
      return [...prev, { ...item, quantity: 1 }];
    });
    triggerNotification(`${item.name} added!`);
  };

  const removeFromCart = (itemId: string) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === itemId);
      if (existing && existing.quantity > 1) {
        return prev.map(i => i.id === itemId ? { ...i, quantity: i.quantity - 1 } : i);
      }
      return prev.filter(i => i.id !== itemId);
    });
  };

  const clearCart = () => setCart([]);

  const triggerNotification = (msg: string) => {
    setShowNotification(msg);
    setTimeout(() => setShowNotification(null), 3000);
  };

  const handlePlaceOrder = async (phone: string, location: string, paymentMethod: 'COD' | 'GPay') => {
    if (cart.length === 0 || !session?.user) return;
    setOrderStatus('processing');

    const subtotal = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    const total = subtotal + 30;

    try {
      const { error } = await supabase.from('orders').insert([{
        user_email: session.user.email,
        phone: phone,
        location: location,
        items: cart,
        total_amount: total,
        status: 'Pending Acceptance',
        payment_method: paymentMethod
      }]);

      if (error) throw error;

      setTimeout(() => {
        setOrderStatus('success');
        setCart([]);
      }, 1500);
    } catch (err) {
      console.error('Failed to save order:', err);
      triggerNotification("Order error. Please retry.");
      setOrderStatus('idle');
    }
  };

  // Menu Management Handlers
  const handleAddNewProduct = (product: Omit<FoodItem, 'id'>) => {
    const newItem: FoodItem = {
      ...product,
      id: Math.random().toString(36).substr(2, 9),
      inStock: product.inStock ?? true
    };
    setItems(prev => [newItem, ...prev]);
    triggerNotification(`${product.name} added to menu!`);
  };

  const handleUpdateProduct = (id: string, updates: Partial<FoodItem>) => {
    setItems(prev => prev.map(item => item.id === id ? { ...item, ...updates } : item));
    triggerNotification("Menu item updated!");
  };

  const handleDeleteProduct = (id: string) => {
    setItems(prev => prev.filter(item => item.id !== id));
    triggerNotification("Item removed from menu");
  };

  const handleToggleStock = (id: string) => {
    setItems(prev => prev.map(item => {
      if (item.id === id) {
        const newState = !item.inStock;
        triggerNotification(`${item.name} is now ${newState ? 'In Stock' : 'Out of Stock'}`);
        return { ...item, inStock: newState };
      }
      return item;
    }));
  };

  const startListening = () => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
      setIsListening(true);
      const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
      const recognition = new SpeechRecognition();
      recognition.lang = 'en-US';
      recognition.continuous = false;
      recognition.onend = () => setIsListening(false);
      recognition.onresult = (event: any) => {
        const transcript = event.results[0][0].transcript;
        setSearchQuery(transcript);
        triggerNotification(`Searched: "${transcript}"`);
      };
      recognition.start();
    } else {
      triggerNotification("Voice search not supported");
    }
  };

  const filteredItems = items.filter(item => 
    item.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
    item.category.toLowerCase().includes(searchQuery.toLowerCase())
  );

  if (authLoading) {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-white">
        <div className="w-10 h-10 border-4 border-orange-500 border-t-transparent rounded-full animate-spin mb-4"></div>
        <p className="text-gray-400 font-medium">Anandam Loading...</p>
      </div>
    );
  }

  if (!session) return <LandingPage />;

  return (
    <div className="flex flex-col h-screen w-full bg-white overflow-hidden relative font-sans">
      <header className="bg-orange-500 text-white shadow-md z-40 w-full shrink-0 transition-all duration-300">
        <div className="max-w-7xl mx-auto px-4 py-3 flex items-center justify-between gap-3">
          <div className="flex flex-col cursor-pointer shrink-0" onClick={() => setActiveTab('home')}>
            <h1 className="text-xl sm:text-2xl font-black tracking-tight leading-tight">Anandam</h1>
            <p className="text-[9px] text-orange-100 flex items-center">
              <i className="fas fa-map-marker-alt mr-1"></i> Samayapuram
            </p>
          </div>

          <div className="flex-1 relative max-w-lg group">
            <div className="relative">
              <input 
                type="text" 
                placeholder="Find a dish..." 
                className="w-full pl-9 pr-9 py-2 rounded-2xl bg-orange-400/30 text-white placeholder-orange-100 border border-orange-400/50 focus:bg-white focus:text-gray-800 focus:placeholder-gray-400 focus:outline-none transition-all text-sm"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
              <i className="fas fa-search absolute left-3 top-1/2 -translate-y-1/2 text-orange-100 pointer-events-none group-focus-within:text-gray-400"></i>
              <button 
                onClick={startListening}
                className={`absolute right-2 top-1/2 -translate-y-1/2 w-7 h-7 flex items-center justify-center rounded-full transition-colors ${isListening ? 'text-red-300 animate-pulse' : 'text-orange-100 group-focus-within:text-orange-500'}`}
              >
                <i className={`fas ${isListening ? 'fa-circle' : 'fa-microphone'}`}></i>
              </button>
            </div>
          </div>

          <button 
            onClick={() => setActiveTab('order')}
            className="bg-white text-orange-600 px-3 py-2 rounded-full text-xs font-black shadow-md flex items-center relative shrink-0"
          >
            <i className="fas fa-basket-shopping sm:mr-2 text-sm"></i>
            <span className="hidden sm:inline">BASKET</span>
            {cartTotalItems > 0 && (
              <span className="ml-1 sm:ml-2 bg-orange-600 text-white w-4 h-4 rounded-full flex items-center justify-center text-[9px]">
                {cartTotalItems}
              </span>
            )}
          </button>
        </div>
      </header>

      <main className="flex-1 overflow-y-auto custom-scrollbar bg-gray-50 pb-24">
        <div className="max-w-7xl mx-auto w-full tab-content">
          {activeTab === 'home' && (
            <HomeTab items={filteredItems} onAdd={addToCart} onInstall={handleInstallClick} showInstallButton={!!installPrompt} />
          )}
          {activeTab === 'order' && (
            <OrderTab 
              cartItems={cart} 
              onAdd={addToCart} 
              onRemove={removeFromCart}
              onClear={clearCart}
              orderStatus={orderStatus}
              onPlaceOrder={handlePlaceOrder}
              onTrackOrder={() => setActiveTab('profile')}
            />
          )}
          {activeTab === 'profile' && session?.user && (
            <ProfileTab 
              user={session.user} 
              onOpenAdmin={() => setActiveTab('admin')} 
              menuItems={items}
              onUpdateItem={handleUpdateProduct}
              onDeleteItem={handleDeleteProduct}
              onToggleStock={handleToggleStock}
            />
          )}
          {activeTab === 'admin' && (
            <AdminTab onAddProduct={handleAddNewProduct} />
          )}
        </div>
      </main>

      {showNotification && (
        <div className="fixed bottom-24 left-1/2 -translate-x-1/2 bg-gray-900 text-white px-6 py-3 rounded-2xl text-xs shadow-2xl z-50 flex items-center animate-in fade-in slide-in-from-bottom-4">
          <i className="fas fa-info-circle mr-2 text-orange-400"></i>
          {showNotification}
        </div>
      )}

      <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-100 z-30 shadow-[0_-4px_10px_rgba(0,0,0,0.05)] rounded-t-3xl shrink-0">
        <div className="max-w-7xl mx-auto">
          <BottomNav activeTab={activeTab === 'admin' ? 'profile' : activeTab} setActiveTab={setActiveTab} cartCount={cartTotalItems} />
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Order, FoodItem } from '../types';
import { supabase } from '../supabase';
import { User } from '@supabase/supabase-js';

interface ProfileTabProps {
  user: User;
  onOpenAdmin?: () => void;
  menuItems: FoodItem[];
  onUpdateItem: (id: string, updates: Partial<FoodItem>) => void;
  onDeleteItem: (id: string) => void;
  onToggleStock: (id: string) => void;
}

const ProfileTab: React.FC<ProfileTabProps> = ({ 
  user, 
  onOpenAdmin, 
  menuItems, 
  onUpdateItem, 
  onDeleteItem, 
  onToggleStock 
}) => {
  const [view, setView] = useState<'profile' | 'history' | 'menu'>('profile');
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(false);
  const [editingItem, setEditingItem] = useState<FoodItem | null>(null);

  useEffect(() => {
    let subscription: any;
    if (view === 'history' && user?.email) {
      fetchOrderHistory();
      subscription = supabase
        .channel('user-orders-channel')
        .on('postgres_changes', { event: 'UPDATE', schema: 'public', table: 'orders', filter: `user_email=eq.${user.email}` }, fetchOrderHistory)
        .subscribe();
    }
    return () => {
      if (subscription) subscription.unsubscribe();
    };
  }, [view, user]);

  const fetchOrderHistory = async () => {
    if (!user?.email) return;
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('orders')
        .select('*')
        .eq('user_email', user.email)
        .order('created_at', { ascending: false });

      if (error) throw error;
      setOrders(data || []);
    } catch (err) {
      console.error('Error fetching history:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
  };

  const handleEditSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingItem) {
      onUpdateItem(editingItem.id, editingItem);
      setEditingItem(null);
    }
  };

  if (!user) return null;

  // History View
  if (view === 'history') {
    return (
      <div className="p-4 sm:p-8 lg:p-12 max-w-4xl mx-auto animate-in fade-in slide-in-from-right-4 duration-300">
        <div className="flex items-center space-x-4 mb-8">
          <button 
            onClick={() => setView('profile')}
            className="w-10 h-10 rounded-full bg-white border border-gray-100 flex items-center justify-center text-gray-400 hover:text-orange-500 transition-all shadow-sm"
          >
            <i className="fas fa-arrow-left"></i>
          </button>
          <h3 className="text-2xl font-extrabold text-gray-800">Order Tracking</h3>
        </div>

        {loading && orders.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-20">
            <div className="w-10 h-10 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div>
            <p className="text-gray-400 mt-4 font-medium italic text-sm">Loading your orders...</p>
          </div>
        ) : orders.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-20 bg-white rounded-3xl border border-dashed border-gray-100">
            <i className="fas fa-history text-4xl text-gray-200 mb-4"></i>
            <p className="text-gray-500 font-bold">No orders yet</p>
          </div>
        ) : (
          <div className="space-y-6">
            {orders.map((order) => (
              <div key={order.id} className="bg-white rounded-3xl p-6 border border-gray-50 shadow-sm relative overflow-hidden">
                <div className="flex justify-between items-start mb-6">
                  <div>
                    <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-widest ${
                      order.status === 'Pending Acceptance' ? 'bg-amber-100 text-amber-600' :
                      order.status === 'Preparing' ? 'bg-blue-100 text-blue-600' :
                      order.status === 'Ready' ? 'bg-green-100 text-green-600' : 'bg-gray-100 text-gray-600'
                    }`}>
                      {order.status}
                    </span>
                    <p className="text-[10px] text-gray-400 font-bold uppercase mt-2">ID: {order.id.slice(0, 8)} • {new Date(order.created_at).toLocaleTimeString()}</p>
                  </div>
                  <p className="text-xl font-black text-orange-500">₹{order.total_amount}</p>
                </div>

                <div className="bg-gray-50 rounded-2xl p-4 space-y-2">
                  {order.items.map((item, idx) => (
                    <div key={idx} className="flex justify-between text-xs">
                      <span className="text-gray-600 font-medium">{item.quantity}x {item.name}</span>
                      <span className="text-gray-400">₹{item.price * item.quantity}</span>
                    </div>
                  ))}
                  <div className="pt-2 border-t border-gray-200 mt-2 flex justify-between items-center">
                    <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">To: {order.location}</span>
                    <span className="text-[10px] font-black text-blue-500 uppercase tracking-widest">{order.payment_method}</span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    );
  }

  // Menu Management View
  if (view === 'menu') {
    return (
      <div className="p-4 sm:p-8 lg:p-12 max-w-5xl mx-auto animate-in fade-in slide-in-from-right-4 duration-300">
        <div className="flex items-center space-x-4 mb-8">
          <button 
            onClick={() => setView('profile')}
            className="w-10 h-10 rounded-full bg-white border border-gray-100 flex items-center justify-center text-gray-400 hover:text-orange-500 transition-all shadow-sm"
          >
            <i className="fas fa-arrow-left"></i>
          </button>
          <h3 className="text-2xl font-extrabold text-gray-800">Menu Management</h3>
        </div>

        <div className="space-y-4">
          {menuItems.map(item => (
            <div key={item.id} className="bg-white rounded-3xl p-4 sm:p-6 border border-gray-50 shadow-sm flex flex-col sm:flex-row items-center gap-6 group">
              <img src={item.image} alt={item.name} className="w-24 h-24 rounded-2xl object-cover shadow-sm" />

              <div className="flex-1 text-center sm:text-left">
                <div className="flex flex-col sm:flex-row sm:items-center sm:gap-3 mb-1 justify-center sm:justify-start">
                  <h4 className="font-black text-gray-900 text-lg">{item.name}</h4>
                  <span className={`text-[10px] font-black px-2 py-0.5 rounded-full uppercase tracking-widest inline-block mx-auto sm:mx-0 ${
                    item.inStock ? 'bg-green-50 text-green-600' : 'bg-red-50 text-red-600'
                  }`}>
                    {item.inStock ? 'In Stock' : 'Out of Stock'}
                  </span>
                </div>
                <p className="text-orange-500 font-bold">₹{item.price}</p>
                <p className="text-xs text-gray-400 font-medium">{item.category}</p>
              </div>

              <div className="flex items-center gap-2">
                {/* Stock Toggle */}
                <button 
                  onClick={() => onToggleStock(item.id)}
                  className={`px-4 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest border-2 transition-all ${
                    item.inStock 
                      ? 'bg-green-500 border-green-500 text-white shadow-lg shadow-green-100' 
                      : 'bg-white border-gray-100 text-gray-400 hover:border-gray-200'
                  }`}
                >
                  {item.inStock ? 'In Stock' : 'Out of Stock'}
                </button>

                {/* Edit */}
                <button 
                  onClick={() => setEditingItem(item)}
                  className="w-11 h-11 bg-gray-50 text-gray-500 rounded-xl flex items-center justify-center hover:bg-orange-50 hover:text-orange-500 transition-all"
                >
                  <i className="fas fa-edit text-sm"></i>
                </button>

                {/* Delete */}
                <button 
                  onClick={() => {
                    if(confirm(`Remove ${item.name} from menu?`)) onDeleteItem(item.id);
                  }}
                  className="w-11 h-11 bg-red-50 text-red-500 rounded-xl flex items-center justify-center hover:bg-red-500 hover:text-white transition-all"
                >
                  <i className="fas fa-trash-alt text-sm"></i>
                </button>
              </div>
            </div>
          ))}
        </div>

        {/* Edit Modal */}
        {editingItem && (
          <div className="fixed inset-0 bg-black/40 backdrop-blur-sm z-50 flex items-center justify-center p-4">
            <div className="bg-white w-full max-w-md rounded-[2.5rem] p-8 shadow-2xl animate-in zoom-in-95 duration-200">
              <div className="flex justify-between items-center mb-8">
                <h3 className="text-2xl font-black text-gray-900">Edit Dish</h3>
                <button onClick={() => setEditingItem(null)} className="text-gray-400 hover:text-gray-600">
                  <i className="fas fa-times text-xl"></i>
                </button>
              </div>
              <form onSubmit={handleEditSubmit} className="space-y-4">
                <div>
                  <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1 mb-2">Item Name</label>
                  <input 
                    type="text" 
                    required 
                    className="w-full px-5 py-3.5 bg-gray-50 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none font-bold text-gray-800" 
                    value={editingItem.name} 
                    onChange={e => setEditingItem({...editingItem, name: e.target.value})} 
                  />
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1 mb-2">Price (₹)</label>
                    <input 
                      type="number" 
                      required 
                      className="w-full px-5 py-3.5 bg-gray-50 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none font-bold text-gray-800" 
                      value={editingItem.price} 
                      onChange={e => setEditingItem({...editingItem, price: parseInt(e.target.value)})} 
                    />
                  </div>
                  <div>
