import React, { useState, useEffect } from 'react';
import { AppTab, CartItem, FoodItem } from './types';
import { FOOD_ITEMS } from './constants';
import HomeTab from './components/HomeTab';
import OrderTab from './components/OrderTab';
import ProfileTab from './components/ProfileTab';
import AdminTab from './components/AdminTab';
import BottomNav from './components/BottomNav';
import LandingPage from './components/LandingPage';
import { supabase } from './supabase';
import { Session } from '@supabase/supabase-js';

const App: React.FC = () => {
  const [session, setSession] = useState<Session | null>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<AppTab>('home');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [showNotification, setShowNotification] = useState<string | null>(null);
  const [items, setItems] = useState<FoodItem[]>(FOOD_ITEMS);
  const [orderStatus, setOrderStatus] = useState<'idle' | 'processing' | 'success'>('idle');
  const [installPrompt, setInstallPrompt] = useState<any>(null);

  const [searchQuery, setSearchQuery] = useState('');
  const [isListening, setIsListening] = useState(false);

  const cartTotalItems = cart.reduce((acc, curr) => acc + curr.quantity, 0);

  useEffect(() => {
    const initAuth = async () => {
      try {
        const { data: { session } } = await supabase.auth.getSession();
        setSession(session);
      } catch (e) {
        console.error('Initial session fetch failed', e);
      } finally {
        setAuthLoading(false);
      }
    };

    initAuth();

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });

    const handleBeforeInstallPrompt = (e: Event) => {
      e.preventDefault();
      setInstallPrompt(e);
    };

    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);

    return () => {
      subscription.unsubscribe();
      window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    };
  }, []);

  const handleInstallClick = async () => {
    if (!installPrompt) return;
    installPrompt.prompt();
    const { outcome } = await installPrompt.userChoice;
    if (outcome === 'accepted') {
      setInstallPrompt(null);
    }
  };

  const addToCart = (item: FoodItem) => {
    if (!item.inStock) {
      triggerNotification(`${item.name} is currently out of stock!`);
      return;
    }
    if (orderStatus === 'success') setOrderStatus('idle');
    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      }
      return [...prev, { ...item, quantity: 1 }];
    });
    triggerNotification(`${item.name} added!`);
  };

  const removeFromCart = (itemId: string) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === itemId);
      if (existing && existing.quantity > 1) {
        return prev.map(i => i.id === itemId ? { ...i, quantity: i.quantity - 1 } : i);
      }
      return prev.filter(i => i.id !== itemId);
    });
  };

  const clearCart = () => setCart([]);

  const triggerNotification = (msg: string) => {
    setShowNotification(msg);
    setTimeout(() => setShowNotification(null), 3000);
  };

  const handlePlaceOrder = async (phone: string, location: string, paymentMethod: 'COD' | 'GPay') => {
    if (cart.length === 0 || !session?.user) return;
    setOrderStatus('processing');

    const subtotal = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    const total = subtotal + 30;

    try {
      const { error } = await supabase.from('orders').insert([{
        user_email: session.user.email,
        phone: phone,
        location: location,
        items: cart,
        total_amount: total,
        status: 'Pending Acceptance',
        payment_method: paymentMethod
      }]);

      if (error) throw error;

      setTimeout(() => {
        setOrderStatus('success');
        setCart([]);
      }, 1500);
    } catch (err) {
      console.error('Failed to save order:', err);
      triggerNotification("Order error. Please retry.");
      setOrderStatus('idle');
    }
  };

  // Menu Management Handlers
  const handleAddNewProduct = (product: Omit<FoodItem, 'id'>) => {
    const newItem: FoodItem = {
      ...product,
      id: Math.random().toString(36).substr(2, 9),
      inStock: true
    };
    setItems(prev => [newItem, ...prev]);
    triggerNotification(`${product.name} added to menu!`);
  };

  const handleUpdateProduct = (id: string, updates: Partial<FoodItem>) => {
    setItems(prev => prev.map(item => item.id === id ? { ...item, ...updates } : item));
    triggerNotification("Menu item updated!");
  };

  const handleDeleteProduct = (id: string) => {
    setItems(prev => prev.filter(item => item.id !== id));
    triggerNotification("Item removed from menu");
  };

  const handleToggleStock = (id: string) => {
    setItems(prev => prev.map(item => {
      if (item.id === id) {
        const newState = !item.inStock;
        triggerNotification(`${item.name} is now ${newState ? 'In Stock' : 'Out of Stock'}`);
        return { ...item, inStock: newState };
      }
      return item;
    }));
  };

  const startListening = () => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
      setIsListening(true);
      const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
      const recognition = new SpeechRecognition();
      recognition.lang = 'en-US';
      recognition.continuous = false;
      recognition.onend = () => setIsListening(false);
      recognition.onresult = (event: any) => {
        const transcript = event.results[0][0].transcript;
        setSearchQuery(transcript);
        triggerNotification(`Searched: "${transcript}"`);
      };
      recognition.start();
    } else {
      triggerNotification("Voice search not supported");
    }
  };

  const filteredItems = items.filter(item => 
    item.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
    item.category.toLowerCase().includes(searchQuery.toLowerCase())
  );

  if (authLoading) {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-white">
        <div className="w-10 h-10 border-4 border-orange-500 border-t-transparent rounded-full animate-spin mb-4"></div>
        <p className="text-gray-400 font-medium">Anandam Loading...</p>
      </div>
    );
  }

  if (!session) return <LandingPage />;

  return (
    <div className="flex flex-col h-screen w-full bg-white overflow-hidden relative font-sans">
      <header className="bg-orange-500 text-white shadow-md z-40 w-full shrink-0 transition-all duration-300">
        <div className="max-w-7xl mx-auto px-4 py-3 flex items-center justify-between gap-3">
          <div className="flex flex-col cursor-pointer shrink-0" onClick={() => setActiveTab('home')}>
            <h1 className="text-xl sm:text-2xl font-black tracking-tight leading-tight">Anandam</h1>
            <p className="text-[9px] text-orange-100 flex items-center">
              <i className="fas fa-map-marker-alt mr-1"></i> Samayapuram
            </p>
          </div>

          <div className="flex-1 relative max-w-lg group">
            <div className="relative">
              <input 
                type="text" 
                placeholder="Find a dish..." 
                className="w-full pl-9 pr-9 py-2 rounded-2xl bg-orange-400/30 text-white placeholder-orange-100 border border-orange-400/50 focus:bg-white focus:text-gray-800 focus:placeholder-gray-400 focus:outline-none transition-all text-sm"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
              <i className="fas fa-search absolute left-3 top-1/2 -translate-y-1/2 text-orange-100 pointer-events-none group-focus-within:text-gray-400"></i>
              <button 
                onClick={startListening}
                className={`absolute right-2 top-1/2 -translate-y-1/2 w-7 h-7 flex items-center justify-center rounded-full transition-colors ${isListening ? 'text-red-300 animate-pulse' : 'text-orange-100 group-focus-within:text-orange-500'}`}
              >
                <i className={`fas ${isListening ? 'fa-circle' : 'fa-microphone'}`}></i>
              </button>
            </div>
          </div>

          <button 
            onClick={() => setActiveTab('order')}
            className="bg-white text-orange-600 px-3 py-2 rounded-full text-xs font-black shadow-md flex items-center relative shrink-0"
          >
            <i className="fas fa-basket-shopping sm:mr-2 text-sm"></i>
            <span className="hidden sm:inline">BASKET</span>
            {cartTotalItems > 0 && (
              <span className="ml-1 sm:ml-2 bg-orange-600 text-white w-4 h-4 rounded-full flex items-center justify-center text-[9px]">
                {cartTotalItems}
              </span>
            )}
          </button>
        </div>
      </header>

      <main className="flex-1 overflow-y-auto custom-scrollbar bg-gray-50 pb-24">
        <div className="max-w-7xl mx-auto w-full tab-content">
          {activeTab === 'home' && (
            <HomeTab items={filteredItems} onAdd={addToCart} onInstall={handleInstallClick} showInstallButton={!!installPrompt} />
          )}
          {activeTab === 'order' && (
            <OrderTab 
              cartItems={cart} 
              onAdd={addToCart} 
              onRemove={removeFromCart}
              onClear={clearCart}
              orderStatus={orderStatus}
              onPlaceOrder={handlePlaceOrder}
              onTrackOrder={() => setActiveTab('profile')}
            />
          )}
          {activeTab === 'profile' && session?.user && (
            <ProfileTab 
              user={session.user} 
              onOpenAdmin={() => setActiveTab('admin')} 
              menuItems={items}
              onUpdateItem={handleUpdateProduct}
              onDeleteItem={handleDeleteProduct}
              onToggleStock={handleToggleStock}
              onAddItem={handleAddNewProduct}
            />
          )}
          {activeTab === 'admin' && (
            <AdminTab />
          )}
        </div>
      </main>

      {showNotification && (
        <div className="fixed bottom-24 left-1/2 -translate-x-1/2 bg-gray-900 text-white px-6 py-3 rounded-2xl text-xs shadow-2xl z-50 flex items-center animate-in fade-in slide-in-from-bottom-4">
          <i className="fas fa-info-circle mr-2 text-orange-400"></i>
          {showNotification}
        </div>
      )}

      <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-100 z-30 shadow-[0_-4px_10px_rgba(0,0,0,0.05)] rounded-t-3xl shrink-0">
        <div className="max-w-7xl mx-auto">
          <BottomNav activeTab={activeTab === 'admin' ? 'profile' : activeTab} setActiveTab={setActiveTab} cartCount={cartTotalItems} />
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { supabase } from '../supabase';
import { Order, FoodItem, OrderStatus } from '../types';

const AdminTab: React.FC = () => {
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchOrders();
    const subscription = supabase
      .channel('admin-orders-channel')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'orders' }, fetchOrders)
      .subscribe();

    return () => {
      subscription.unsubscribe();
    };
  }, []);

  const fetchOrders = async () => {
    try {
      const { data, error } = await supabase
        .from('orders')
        .select('*')
        .order('created_at', { ascending: false });
      if (error) throw error;
      setOrders(data || []);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const updateOrderStatus = async (orderId: string, newStatus: OrderStatus) => {
    try {
      const { error } = await supabase
        .from('orders')
        .update({ status: newStatus })
        .eq('id', orderId);
      if (error) throw error;
      fetchOrders();
    } catch (err) {
      console.error('Status update failed:', err);
    }
  };

  return (
    <div className="p-4 sm:p-8 lg:p-12 max-w-6xl mx-auto space-y-12">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black text-gray-900 tracking-tight">Kitchen Dashboard</h2>
          <p className="text-gray-500 font-medium">Hotel Anandam Operations</p>
        </div>
      </div>

      <div className="space-y-6">
        <h3 className="text-xl font-bold text-gray-800">Active Orders</h3>
        {loading ? (
          <div className="py-20 flex flex-col items-center">
            <div className="w-10 h-10 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div>
          </div>
        ) : orders.length === 0 ? (
          <div className="bg-white p-20 rounded-3xl border border-dashed border-gray-200 text-center">
            <i className="fas fa-box-open text-4xl text-gray-200 mb-4"></i>
            <p className="text-gray-400 font-bold">Waiting for new orders...</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
