                </div>

                <div className="space-y-4 mb-6">
                  <div className="flex items-center space-x-3">
                    <div className="w-8 h-8 bg-gray-50 rounded-lg flex items-center justify-center text-gray-400 text-xs">
                      <i className="fas fa-location-dot"></i>
                    </div>
                    <div>
                      <p className="text-xs font-bold text-gray-800">{order.location}</p>
