                <div className="bg-gray-50 rounded-2xl p-4 space-y-2 flex-1">
                  <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2">Order Items</p>
                  {order.items.map((item, idx) => (
                    <div key={idx} className="flex justify-between items-center text-xs">
                      <span className="text-gray-600 font-medium"><span className="text-orange-500 font-black">{item.quantity}x</span> {item.name}</span>
                      <span className="text-gray-400">₹{item.price * item.quantity}</span>
                    </div>
                  ))}
                </div>

                <div className="mt-6 space-y-2">
                  {order.status === 'Pending Acceptance' && (
                    <button 
                      onClick={() => updateOrderStatus(order.id, 'Preparing')}
                      className="w-full bg-blue-600 text-white py-3.5 rounded-xl font-bold text-sm shadow-lg shadow-blue-50 active:scale-95 transition-all flex items-center justify-center"
                    >
                      <i className="fas fa-check-circle mr-2"></i>
                      Accept Order
                    </button>
                  )}
                  {order.status === 'Preparing' && (
                    <button 
                      onClick={() => updateOrderStatus(order.id, 'Ready')}
                      className="w-full bg-green-600 text-white py-3.5 rounded-xl font-bold text-sm shadow-lg shadow-green-50 active:scale-95 transition-all flex items-center justify-center"
                    >
                      <i className="fas fa-bell mr-2"></i>
                      Mark as Ready
                    </button>
                  )}
                  {order.status === 'Ready' && (
                    <button 
                      onClick={() => updateOrderStatus(order.id, 'Delivered')}
                      className="w-full bg-gray-900 text-white py-3.5 rounded-xl font-bold text-sm active:scale-95 transition-all flex items-center justify-center"
                    >
                      <i className="fas fa-truck mr-2"></i>
                      Mark as Delivered
                    </button>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminTab;

import React, { useState, useEffect } from 'react';
import { Order, FoodItem } from '../types';
import { supabase } from '../supabase';
import { User } from '@supabase/supabase-js';

interface ProfileTabProps {
  user: User;
  onOpenAdmin?: () => void;
  menuItems: FoodItem[];
  onUpdateItem: (id: string, updates: Partial<FoodItem>) => void;
  onDeleteItem: (id: string) => void;
  onToggleStock: (id: string) => void;
  onAddItem: (product: Omit<FoodItem, 'id'>) => void;
}

const ProfileTab: React.FC<ProfileTabProps> = ({ 
  user, 
  onOpenAdmin, 
  menuItems, 
  onUpdateItem, 
  onDeleteItem, 
  onToggleStock,
  onAddItem
}) => {
  const [view, setView] = useState<'profile' | 'history' | 'menu'>('profile');
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(false);
  const [editingItem, setEditingItem] = useState<FoodItem | null>(null);
  const [showAddModal, setShowAddModal] = useState(false);
  const [menuSearch, setMenuSearch] = useState('');

  const [newProduct, setNewProduct] = useState({
    name: '',
    price: 0,
    category: 'Rice',
    description: '',
    image: ''
  });

  useEffect(() => {
    let subscription: any;
    if (view === 'history' && user?.email) {
      fetchOrderHistory();
      subscription = supabase
        .channel('user-orders-channel')
        .on('postgres_changes', { event: 'UPDATE', schema: 'public', table: 'orders', filter: `user_email=eq.${user.email}` }, fetchOrderHistory)
        .subscribe();
    }
    return () => {
      if (subscription) subscription.unsubscribe();
    };
  }, [view, user]);

  const fetchOrderHistory = async () => {
    if (!user?.email) return;
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('orders')
        .select('*')
        .eq('user_email', user.email)
        .order('created_at', { ascending: false });

      if (error) throw error;
      setOrders(data || []);
    } catch (err) {
      console.error('Error fetching history:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
  };

  const handleEditSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingItem) {
      onUpdateItem(editingItem.id, editingItem);
      setEditingItem(null);
    }
  };

  const handleAddSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newProduct.name || newProduct.price <= 0) return;

    onAddItem({
      ...newProduct,
      image: newProduct.image.trim() || 'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?auto=format&fit=crop&w=400&q=80'
    });

    setNewProduct({
      name: '',
      price: 0,
      category: 'Rice',
      description: '',
      image: ''
    });
    setShowAddModal(false);
  };

  const filteredMenu = menuItems.filter(item => 
    item.name.toLowerCase().includes(menuSearch.toLowerCase()) ||
    item.category.toLowerCase().includes(menuSearch.toLowerCase())
  );

  if (!user) return null;

  // History View
  if (view === 'history') {
    return (
      <div className="p-4 sm:p-8 lg:p-12 max-w-4xl mx-auto animate-in fade-in slide-in-from-right-4 duration-300">
        <div className="flex items-center space-x-4 mb-8">
          <button 
            onClick={() => setView('profile')}
            className="w-10 h-10 rounded-full bg-white border border-gray-100 flex items-center justify-center text-gray-400 hover:text-orange-500 transition-all shadow-sm"
          >
            <i className="fas fa-arrow-left"></i>
          </button>
          <h3 className="text-2xl font-extrabold text-gray-800">Order Tracking</h3>
        </div>

        {loading && orders.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-20">
            <div className="w-10 h-10 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div>
            <p className="text-gray-400 mt-4 font-medium italic text-sm">Loading your orders...</p>
          </div>
        ) : orders.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-20 bg-white rounded-3xl border border-dashed border-gray-100">
            <i className="fas fa-history text-4xl text-gray-200 mb-4"></i>
            <p className="text-gray-500 font-bold">No orders yet</p>
          </div>
        ) : (
          <div className="space-y-6">
            {orders.map((order) => (
              <div key={order.id} className="bg-white rounded-3xl p-6 border border-gray-50 shadow-sm relative overflow-hidden">
                <div className="flex justify-between items-start mb-6">
                  <div>
                    <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-widest ${
                      order.status === 'Pending Acceptance' ? 'bg-amber-100 text-amber-600' :
                      order.status === 'Preparing' ? 'bg-blue-100 text-blue-600' :
                      order.status === 'Ready' ? 'bg-green-100 text-green-600' : 'bg-gray-100 text-gray-600'
                    }`}>
                      {order.status}
                    </span>
                    <p className="text-[10px] text-gray-400 font-bold uppercase mt-2">ID: {order.id.slice(0, 8)} • {new Date(order.created_at).toLocaleTimeString()}</p>
                  </div>
                  <p className="text-xl font-black text-orange-500">₹{order.total_amount}</p>
                </div>

                <div className="bg-gray-50 rounded-2xl p-4 space-y-2">
                  {order.items.map((item, idx) => (
                    <div key={idx} className="flex justify-between text-xs">
                      <span className="text-gray-600 font-medium">{item.quantity}x {item.name}</span>
                      <span className="text-gray-400">₹{item.price * item.quantity}</span>
                    </div>
                  ))}
                  <div className="pt-2 border-t border-gray-200 mt-2 flex justify-between items-center">
                    <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">To: {order.location}</span>
                    <span className="text-[10px] font-black text-blue-500 uppercase tracking-widest">{order.payment_method}</span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    );
  }

  // Menu Management View
  if (view === 'menu') {
    return (
      <div className="p-4 sm:p-8 lg:p-12 max-w-5xl mx-auto animate-in fade-in slide-in-from-right-4 duration-300">
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-6 mb-12">
          <div className="flex items-center space-x-4">
            <button 
              onClick={() => setView('profile')}
              className="w-10 h-10 rounded-full bg-white border border-gray-100 flex items-center justify-center text-gray-400 hover:text-orange-500 transition-all shadow-sm"
            >
              <i className="fas fa-arrow-left"></i>
            </button>
            <h3 className="text-2xl font-extrabold text-gray-800">Menu Management</h3>
          </div>
          <button 
            onClick={() => setShowAddModal(true)}
            className="bg-orange-500 text-white px-8 py-3.5 rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg shadow-orange-100 hover:bg-orange-600 active:scale-95 transition-all flex items-center justify-center space-x-2"
          >
            <i className="fas fa-plus"></i>
            <span>Add New Dish</span>
          </button>
        </div>

        {/* Search Bar */}
        <div className="relative mb-8 group">
          <input 
            type="text" 
            placeholder="Search menu items..." 
            className="w-full pl-12 pr-6 py-4 bg-white border border-gray-100 rounded-2xl focus:outline-none focus:ring-2 focus:ring-orange-500 shadow-sm transition-all font-medium text-gray-700"
            value={menuSearch}
            onChange={(e) => setMenuSearch(e.target.value)}
          />
          <i className="fas fa-search absolute left-5 top-1/2 -translate-y-1/2 text-gray-300 group-focus-within:text-orange-500 transition-colors"></i>
        </div>

        <div className="space-y-4">
          {filteredMenu.length === 0 ? (
            <div className="py-20 text-center bg-white rounded-[2.5rem] border border-dashed border-gray-200">
              <i className="fas fa-search text-4xl text-gray-200 mb-4"></i>
              <p className="text-gray-400 font-bold uppercase text-xs tracking-widest">No matching dishes found</p>
            </div>
          ) : (
            filteredMenu.map(item => (
              <div key={item.id} className="bg-white rounded-3xl p-4 sm:p-6 border border-gray-50 shadow-sm flex flex-col sm:flex-row items-center gap-6 group">
                <img src={item.image} alt={item.name} className="w-24 h-24 rounded-2xl object-cover shadow-sm" />

                <div className="flex-1 text-center sm:text-left">
                  <div className="flex flex-col sm:flex-row sm:items-center sm:gap-3 mb-1 justify-center sm:justify-start">
                    <h4 className="font-black text-gray-900 text-lg">{item.name}</h4>
                    <span className={`text-[10px] font-black px-2 py-0.5 rounded-full uppercase tracking-widest inline-block mx-auto sm:mx-0 ${
                      item.inStock ? 'bg-green-50 text-green-600' : 'bg-red-50 text-red-600'
                    }`}>
                      {item.inStock ? 'In Stock' : 'Out of Stock'}
                    </span>
                  </div>
                  <p className="text-orange-500 font-bold">₹{item.price}</p>
                  <p className="text-xs text-gray-400 font-medium">{item.category}</p>
                </div>

                <div className="flex items-center gap-2">
                  <button 
                    onClick={() => onToggleStock(item.id)}
                    className={`px-4 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest border-2 transition-all ${
                      item.inStock 
                        ? 'bg-green-500 border-green-500 text-white shadow-lg shadow-green-100' 
                        : 'bg-white border-gray-100 text-gray-400 hover:border-gray-200'
                    }`}
                  >
                    {item.inStock ? 'In Stock' : 'Out of Stock'}
                  </button>

                  <button 
                    onClick={() => setEditingItem(item)}
                    className="w-11 h-11 bg-gray-50 text-gray-500 rounded-xl flex items-center justify-center hover:bg-orange-50 hover:text-orange-500 transition-all"
                  >
                    <i className="fas fa-edit text-sm"></i>
                  </button>

                  <button 
                    onClick={() => {
                      if(confirm(`Remove ${item.name} from menu?`)) onDeleteItem(item.id);
                    }}
                    className="w-11 h-11 bg-red-50 text-red-500 rounded-xl flex items-center justify-center hover:bg-red-500 hover:text-white transition-all"
                  >
                    <i className="fas fa-trash-alt text-sm"></i>
                  </button>
                </div>
              </div>
            ))
          )}
        </div>

        {/* Add Modal */}
        {showAddModal && (
          <div className="fixed inset-0 bg-black/40 backdrop-blur-sm z-50 flex items-center justify-center p-4">
            <div className="bg-white w-full max-w-md rounded-[2.5rem] p-8 shadow-2xl animate-in zoom-in-95 duration-200">
              <div className="flex justify-between items-center mb-8">
                <h3 className="text-2xl font-black text-gray-900">New Dish</h3>
                <button onClick={() => setShowAddModal(false)} className="text-gray-400 hover:text-gray-600">
                  <i className="fas fa-times text-xl"></i>
                </button>
              </div>
              <form onSubmit={handleAddSubmit} className="space-y-4">
                <div>
                  <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1 mb-2">Item Name</label>
                  <input type="text" required className="w-full px-5 py-3.5 bg-gray-50 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none font-bold text-gray-800" value={newProduct.name} onChange={e => setNewProduct({...newProduct, name: e.target.value})} />
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1 mb-2">Price (₹)</label>
                    <input type="number" required className="w-full px-5 py-3.5 bg-gray-50 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none font-bold text-gray-800" value={newProduct.price} onChange={e => setNewProduct({...newProduct, price: parseInt(e.target.value)})} />
                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1 mb-2">Category</label>
                    <select className="w-full px-5 py-3.5 bg-gray-50 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none font-bold text-gray-800 appearance-none" value={newProduct.category} onChange={e => setNewProduct({...newProduct, category: e.target.value})}>
                      <option>Rice</option><option>Noodles</option><option>Breads</option><option>Specials</option><option>Drinks</option>
                    </select>
                  </div>
                </div>
                <div>
                  <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1 mb-2">Image URL</label>
                  <input type="url" className="w-full px-5 py-3.5 bg-gray-50 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none font-bold text-gray-800" value={newProduct.image} onChange={e => setNewProduct({...newProduct, image: e.target.value})} />
                </div>
                <button type="submit" className="w-full bg-orange-500 text-white py-4 rounded-2xl font-bold text-lg shadow-xl shadow-orange-100 mt-4 hover:bg-orange-600 transition-all">Create Product</button>
              </form>
            </div>
          </div>
        )}

        {/* Edit Modal */}
        {editingItem && (
          <div className="fixed inset-0 bg-black/40 backdrop-blur-sm z-50 flex items-center justify-center p-4">
            <div className="bg-white w-full max-w-md rounded-[2.5rem] p-8 shadow-2xl animate-in zoom-in-95 duration-200">
              <div className="flex justify-between items-center mb-8">
                <h3 className="text-2xl font-black text-gray-900">Edit Dish</h3>
