                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1 mb-2">Price (₹)</label>
                    <input type="number" required className="w-full px-5 py-3.5 bg-gray-50 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none font-bold text-gray-800" value={editingItem.price} onChange={e => setEditingItem({...editingItem, price: parseInt(e.target.value)})} />
