                    <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1 mb-2">Category</label>
                    <select className="w-full px-5 py-3.5 bg-gray-50 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none font-bold text-gray-800 appearance-none" value={editingItem.category} onChange={e => setEditingItem({...editingItem, category: e.target.value})}>
                      <option>Rice</option><option>Noodles</option><option>Breads</option><option>Specials</option><option>Drinks</option>
                    </select>
                  </div>
