                </div>
                <button type="submit" className="w-full bg-orange-500 text-white py-4 rounded-2xl font-bold text-lg shadow-xl shadow-orange-100 mt-4 hover:bg-orange-600 transition-all">Save Changes</button>
              </form>
            </div>
          </div>
        )}
      </div>
    );
  }

  // Main Profile View
  return (
    <div className="p-4 sm:p-8 lg:p-12 max-w-4xl mx-auto">
      <div className="flex flex-col items-center text-center mb-12 sm:mb-16">
        <div className="relative inline-block mb-6">
          <div className="w-28 h-28 sm:w-36 sm:h-36 rounded-full border-4 border-orange-50 p-1 relative overflow-hidden shadow-lg">
            <img src={user.user_metadata?.avatar_url || `https://i.pravatar.cc/150?u=${user.id}`} alt="User" className="w-full h-full rounded-full object-cover" />
          </div>
        </div>
        <h3 className="text-3xl font-black text-gray-800 mb-1">{user.user_metadata?.full_name || user.email?.split('@')[0]}</h3>
        <p className="text-gray-500 font-medium text-sm">{user.email}</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="space-y-6">
          <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Orders & Management</h4>
          <button 
            onClick={() => setView('history')}
            className="w-full py-5 bg-white border border-gray-100 text-gray-700 rounded-3xl font-bold text-sm hover:bg-gray-50 flex items-center px-6 space-x-4 shadow-sm group transition-all"
          >
            <div className="w-12 h-12 bg-orange-50 text-orange-500 rounded-2xl flex items-center justify-center transition-transform group-hover:scale-110">
              <i className="fas fa-truck-fast"></i>
            </div>
            <div className="text-left">
              <span className="block font-black text-gray-900">Track Current Orders</span>
              <span className="text-[10px] text-gray-400 uppercase">View Status & History</span>
            </div>
          </button>

          <button 
            onClick={() => setView('menu')}
            className="w-full py-5 bg-white border border-gray-100 text-gray-700 rounded-3xl font-bold text-sm hover:bg-gray-50 flex items-center px-6 space-x-4 shadow-sm group transition-all"
          >
            <div className="w-12 h-12 bg-blue-50 text-blue-500 rounded-2xl flex items-center justify-center transition-transform group-hover:rotate-6">
              <i className="fas fa-list-check"></i>
            </div>
            <div className="text-left">
              <span className="block font-black text-gray-900">Menu Management</span>
              <span className="text-[10px] text-gray-400 uppercase">Stock, Edit & Remove</span>
            </div>
          </button>

          <button 
            onClick={onOpenAdmin}
            className="w-full py-5 bg-gray-900 text-white rounded-3xl font-bold text-sm hover:bg-black flex items-center px-6 space-x-4 shadow-xl group transition-all"
          >
            <div className="w-12 h-12 bg-gray-800 text-orange-400 rounded-2xl flex items-center justify-center transition-transform group-hover:rotate-12">
              <i className="fas fa-utensils"></i>
            </div>
            <div className="text-left">
              <span className="block font-black">Kitchen Login</span>
              <span className="text-[10px] text-gray-500 uppercase">Restaurant Management</span>
            </div>
          </button>
        </div>

        <div className="space-y-6">
          <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Settings</h4>
          <button 
            onClick={handleLogout}
            className="w-full py-5 border-2 border-red-50 text-red-500 rounded-3xl font-bold text-sm hover:bg-red-50 flex items-center px-6 space-x-4 transition-all"
          >
            <div className="w-12 h-12 bg-red-100 text-red-600 rounded-2xl flex items-center justify-center"><i className="fas fa-power-off"></i></div>
            <span className="font-black">Logout</span>
          </button>
        </div>
      </div>
    </div>
  );
};

