};

export default App;

import React, { useState, useEffect } from 'react';
import { AppTab, CartItem, FoodItem } from './types';
import { FOOD_ITEMS } from './constants';
import HomeTab from './components/HomeTab';
import OrderTab from './components/OrderTab';
import ProfileTab from './components/ProfileTab';
import AdminTab from './components/AdminTab';
import BottomNav from './components/BottomNav';
import LandingPage from './components/LandingPage';
import { supabase } from './supabase';
import { Session } from '@supabase/supabase-js';

const App: React.FC = () => {
  const [session, setSession] = useState<Session | null>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<AppTab>('home');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [showNotification, setShowNotification] = useState<{msg: string, type: 'info' | 'error' | 'success'} | null>(null);
  const [items, setItems] = useState<FoodItem[]>([]);
  const [menuLoading, setMenuLoading] = useState(true);
  const [orderStatus, setOrderStatus] = useState<'idle' | 'processing' | 'success'>('idle');
  const [installPrompt, setInstallPrompt] = useState<any>(null);
  const [dbError, setDbError] = useState<string | null>(null);

  const [searchQuery, setSearchQuery] = useState('');
  const [isListening, setIsListening] = useState(false);

  const cartTotalItems = cart.reduce((acc, curr) => acc + curr.quantity, 0);

  useEffect(() => {
    const initAuth = async () => {
      try {
        const { data: { session } } = await supabase.auth.getSession();
        setSession(session);
      } catch (e) {
        console.error('Initial session fetch failed', e);
      } finally {
        setAuthLoading(false);
      }
    };

    initAuth();
    fetchMenuItems();

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });

    const menuSubscription = supabase
      .channel('menu-changes')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'products' }, fetchMenuItems)
      .subscribe();

    const handleBeforeInstallPrompt = (e: Event) => {
      e.preventDefault();
      setInstallPrompt(e);
    };

    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);

    return () => {
      subscription.unsubscribe();
      menuSubscription.unsubscribe();
      window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    };
  }, []);

  const fetchMenuItems = async () => {
    try {
      const { data, error } = await supabase
        .from('products')
        .select('*')
        .order('created_at', { ascending: false });

      if (error) {
        if (error.code === 'PGRST205') {
          setDbError("Database table 'products' missing.");
        }
        throw error;
      }

      setDbError(null);
      if (data && data.length > 0) {
        setItems(data);
      } else {
        setItems(FOOD_ITEMS);
      }
    } catch (err) {
      console.warn('DB Fetch failed, using fallback items');
      if (items.length === 0) setItems(FOOD_ITEMS);
    } finally {
      setMenuLoading(false);
    }
  };

  const triggerNotification = (msg: string, type: 'info' | 'error' | 'success' = 'info') => {
    setShowNotification({ msg, type });
    setTimeout(() => setShowNotification(null), 3000);
  };

  const addToCart = (item: FoodItem) => {
    if (!item.inStock) {
      triggerNotification(`${item.name} is out of stock!`, 'error');
      return;
    }
    if (orderStatus === 'success') setOrderStatus('idle');
    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      }
      return [...prev, { ...item, quantity: 1 }];
    });
    triggerNotification(`${item.name} added!`, 'success');
  };

  const removeFromCart = (itemId: string) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === itemId);
      if (existing && existing.quantity > 1) {
        return prev.map(i => i.id === itemId ? { ...i, quantity: i.quantity - 1 } : i);
      }
      return prev.filter(i => i.id !== itemId);
    });
  };

  const clearCart = () => setCart([]);

  const handlePlaceOrder = async (phone: string, location: string, paymentMethod: 'COD' | 'GPay') => {
    if (cart.length === 0 || !session?.user) return;
    setOrderStatus('processing');
    const total = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0) + 30;

    try {
      const { error } = await supabase.from('orders').insert([{
        user_email: session.user.email,
        phone, location, items: cart, total_amount: total,
        status: 'Pending Acceptance', payment_method: paymentMethod
      }]);
      if (error) throw error;
      setTimeout(() => { setOrderStatus('success'); setCart([]); }, 1500);
    } catch (err) {
      triggerNotification("Order failed. Please retry.", 'error');
      setOrderStatus('idle');
    }
  };

  const handleAddNewProduct = async (product: Omit<FoodItem, 'id'>) => {
    try {
      const { data, error } = await supabase.from('products').insert([{ ...product, inStock: true }]).select();
      if (error) throw error;
      if (data) {
        setItems(prev => [data[0], ...prev]);
        triggerNotification(`${product.name} saved!`, 'success');
      }
    } catch (err: any) {
      triggerNotification("Table missing - item saved only for this session", 'error');
      const tempItem = { ...product, id: Math.random().toString(36).substr(2, 9), inStock: true };
      setItems(prev => [tempItem, ...prev]);
    }
  };

  const handleUpdateProduct = async (id: string, updates: Partial<FoodItem>) => {
    try {
      const { error } = await supabase.from('products').update(updates).eq('id', id);
      if (error) throw error;
      setItems(prev => prev.map(item => item.id === id ? { ...item, ...updates } : item));
      triggerNotification("Updated successfully", 'success');
    } catch (err) {
      triggerNotification("Update failed - local only", 'error');
      setItems(prev => prev.map(item => item.id === id ? { ...item, ...updates } : item));
    }
  };

  const handleDeleteProduct = async (id: string) => {
    try {
      const { error } = await supabase.from('products').delete().eq('id', id);
      if (error) throw error;
      setItems(prev => prev.filter(item => item.id !== id));
      triggerNotification("Item removed", 'success');
    } catch (err) {
      triggerNotification("Delete failed - local only", 'error');
      setItems(prev => prev.filter(item => item.id !== id));
    }
  };

  const handleToggleStock = async (id: string) => {
    const item = items.find(i => i.id === id);
    if (!item) return;
    const newStatus = !item.inStock;
    try {
      const { error } = await supabase.from('products').update({ inStock: newStatus }).eq('id', id);
      if (error) throw error;
      setItems(prev => prev.map(i => i.id === id ? { ...i, inStock: newStatus } : i));
      triggerNotification(`${item.name} is now ${newStatus ? 'In Stock' : 'Out of Stock'}`, 'info');
    } catch (err) {
      triggerNotification("Stock update failed - local only", 'error');
      setItems(prev => prev.map(i => i.id === id ? { ...i, inStock: newStatus } : i));
    }
  };

  const handleInstallClick = async () => {
    if (!installPrompt) return;
    installPrompt.prompt();
    await installPrompt.userChoice;
    setInstallPrompt(null);
  };

  const startListening = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      setIsListening(true);
      const recognition = new SpeechRecognition();
      recognition.onend = () => setIsListening(false);
      recognition.onresult = (e: any) => setSearchQuery(e.results[0][0].transcript);
      recognition.start();
    } else triggerNotification("Voice search not supported", 'error');
  };

  if (authLoading || menuLoading) {
    return <div className="h-screen flex items-center justify-center"><div className="w-10 h-10 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div></div>;
  }

  if (!session) return <LandingPage />;

  return (
    <div className="flex flex-col h-screen w-full bg-white overflow-hidden relative font-sans">
      <header className="bg-orange-500 text-white shadow-md z-40 w-full shrink-0">
        <div className="max-w-7xl mx-auto px-4 py-3 flex items-center justify-between gap-3">
          <div className="flex flex-col cursor-pointer" onClick={() => setActiveTab('home')}>
            <h1 className="text-xl sm:text-2xl font-black">Anandam</h1>
          </div>
          <div className="flex-1 relative max-w-lg">
            <input type="text" placeholder="Find a dish..." className="w-full pl-9 pr-9 py-2 rounded-2xl bg-orange-400/30 text-white placeholder-orange-100 border-none focus:bg-white focus:text-gray-800 text-sm" value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} />
            <i className="fas fa-search absolute left-3 top-1/2 -translate-y-1/2 text-orange-100"></i>
            <button onClick={startListening} className={`absolute right-2 top-1/2 -translate-y-1/2 w-7 h-7 flex items-center justify-center rounded-full ${isListening ? 'text-red-300 animate-pulse' : 'text-orange-100'}`}><i className={`fas ${isListening ? 'fa-circle' : 'fa-microphone'}`}></i></button>
          </div>
          <button onClick={() => setActiveTab('order')} className="bg-white text-orange-600 px-3 py-2 rounded-full text-xs font-black flex items-center relative">
            <i className="fas fa-basket-shopping sm:mr-2"></i>
            <span className="hidden sm:inline">BASKET</span>
            {cartTotalItems > 0 && <span className="ml-2 bg-orange-600 text-white w-4 h-4 rounded-full flex items-center justify-center text-[9px]">{cartTotalItems}</span>}
          </button>
        </div>
      </header>
      <main className="flex-1 overflow-y-auto bg-gray-50 pb-24">
        {activeTab === 'home' && <HomeTab items={filteredItems} onAdd={addToCart} onInstall={handleInstallClick} showInstallButton={!!installPrompt} />}
        {activeTab === 'order' && <OrderTab cartItems={cart} onAdd={addToCart} onRemove={removeFromCart} onClear={clearCart} orderStatus={orderStatus} onPlaceOrder={handlePlaceOrder} onTrackOrder={() => setActiveTab('profile')} />}
        {activeTab === 'profile' && session?.user && <ProfileTab user={session.user} onOpenAdmin={() => setActiveTab('admin')} menuItems={items} onUpdateItem={handleUpdateProduct} onDeleteItem={handleDeleteProduct} onToggleStock={handleToggleStock} onAddItem={handleAddNewProduct} dbError={dbError} />}
        {activeTab === 'admin' && <AdminTab />}
      </main>
      {showNotification && (
        <div className={`fixed bottom-24 left-1/2 -translate-x-1/2 px-6 py-3 rounded-2xl text-xs shadow-2xl z-50 flex items-center animate-in fade-in slide-in-from-bottom-4 ${showNotification.type === 'error' ? 'bg-red-600 text-white' : showNotification.type === 'success' ? 'bg-green-600 text-white' : 'bg-gray-900 text-white'}`}>
          <i className={`fas mr-2 ${showNotification.type === 'error' ? 'fa-circle-exclamation' : showNotification.type === 'success' ? 'fa-circle-check' : 'fa-info-circle text-orange-400'}`}></i>
          {showNotification.msg}
        </div>
      )}
      <div className="fixed bottom-0 left-0 right-0 bg-white border-t z-30"><BottomNav activeTab={activeTab === 'admin' ? 'profile' : activeTab} setActiveTab={setActiveTab} cartCount={cartTotalItems} /></div>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Order, FoodItem } from '../types';
import { supabase } from '../supabase';
import { User } from '@supabase/supabase-js';

interface ProfileTabProps {
  user: User;
  onOpenAdmin?: () => void;
  menuItems: FoodItem[];
  onUpdateItem: (id: string, updates: Partial<FoodItem>) => void;
  onDeleteItem: (id: string) => void;
  onToggleStock: (id: string) => void;
  onAddItem: (product: Omit<FoodItem, 'id'>) => void;
  dbError?: string | null;
}

const ProfileTab: React.FC<ProfileTabProps> = ({ 
  user, 
  onOpenAdmin, 
  menuItems, 
  onUpdateItem, 
  onDeleteItem, 
  onToggleStock,
  onAddItem,
  dbError
}) => {
  const [view, setView] = useState<'profile' | 'history' | 'menu'>('profile');
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(false);
  const [editingItem, setEditingItem] = useState<FoodItem | null>(null);
  const [showAddModal, setShowAddModal] = useState(false);
  const [menuSearch, setMenuSearch] = useState('');

  const [newProduct, setNewProduct] = useState({
    name: '',
    price: 0,
    category: 'Rice',
    description: '',
    image: ''
  });

  useEffect(() => {
    let subscription: any;
    if (view === 'history' && user?.email) {
      fetchOrderHistory();
      subscription = supabase
        .channel('user-orders-channel')
        .on('postgres_changes', { event: 'UPDATE', schema: 'public', table: 'orders', filter: `user_email=eq.${user.email}` }, fetchOrderHistory)
        .subscribe();
    }
    return () => { if (subscription) subscription.unsubscribe(); };
  }, [view, user]);

  const fetchOrderHistory = async () => {
    if (!user?.email) return;
    setLoading(true);
    try {
      const { data, error } = await supabase.from('orders').select('*').eq('user_email', user.email).order('created_at', { ascending: false });
      if (error) throw error;
      setOrders(data || []);
    } catch (err) { console.error(err); } finally { setLoading(false); }
  };

  const handleEditSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingItem) {
      onUpdateItem(editingItem.id, editingItem);
      setEditingItem(null);
    }
  };

  const handleAddSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newProduct.name || newProduct.price <= 0) return;
    onAddItem({
      ...newProduct,
      image: newProduct.image.trim() || 'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?auto=format&fit=crop&w=400&q=80'
    });
    setNewProduct({ name: '', price: 0, category: 'Rice', description: '', image: '' });
    setShowAddModal(false);
  };

  const filteredMenu = menuItems.filter(item => 
    item.name.toLowerCase().includes(menuSearch.toLowerCase()) ||
    item.category.toLowerCase().includes(menuSearch.toLowerCase())
  );

  if (view === 'history') {
    return (
      <div className="p-4 sm:p-8 lg:p-12 max-w-4xl mx-auto animate-in fade-in slide-in-from-right-4">
        <div className="flex items-center space-x-4 mb-8">
          <button onClick={() => setView('profile')} className="w-10 h-10 rounded-full bg-white border flex items-center justify-center text-gray-400 hover:text-orange-500 transition-all"><i className="fas fa-arrow-left"></i></button>
          <h3 className="text-2xl font-extrabold text-gray-800">Order Tracking</h3>
        </div>
        <div className="space-y-6">
          {orders.map((order) => (
            <div key={order.id} className="bg-white rounded-3xl p-6 border shadow-sm">
              <div className="flex justify-between items-start mb-6">
                <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase ${order.status === 'Ready' ? 'bg-green-100 text-green-600' : 'bg-amber-100 text-amber-600'}`}>{order.status}</span>
                <p className="text-xl font-black text-orange-500">₹{order.total_amount}</p>
              </div>
              <div className="bg-gray-50 rounded-2xl p-4 space-y-2">
                {order.items.map((item, idx) => (
                  <div key={idx} className="flex justify-between text-xs">
                    <span>{item.quantity}x {item.name}</span>
                    <span className="text-gray-400">₹{item.price * item.quantity}</span>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  }

  if (view === 'menu') {
    return (
      <div className="p-4 sm:p-8 lg:p-12 max-w-5xl mx-auto animate-in fade-in slide-in-from-right-4">
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-6 mb-8">
          <div className="flex items-center space-x-4">
            <button onClick={() => setView('profile')} className="w-10 h-10 rounded-full bg-white border flex items-center justify-center text-gray-400 hover:text-orange-500 transition-all"><i className="fas fa-arrow-left"></i></button>
            <h3 className="text-2xl font-extrabold text-gray-800">Menu Management</h3>
          </div>
          <button onClick={() => setShowAddModal(true)} className="bg-orange-500 text-white px-8 py-3.5 rounded-2xl font-black text-xs uppercase shadow-lg hover:bg-orange-600 transition-all"><i className="fas fa-plus mr-2"></i>New Dish</button>
        </div>

        {dbError && (
          <div className="mb-8 p-4 bg-amber-50 border border-amber-200 rounded-2xl flex items-start space-x-4 text-amber-800">
            <i className="fas fa-database mt-1"></i>
            <div>
              <p className="text-sm font-bold">Local Sync Only</p>
              <p className="text-xs mt-1">The 'products' table is missing. Your changes will not be saved permanently until the table is created.</p>
            </div>
          </div>
        )}

        <div className="relative mb-8">
          <input type="text" placeholder="Search menu..." className="w-full pl-12 pr-6 py-4 bg-white border rounded-2xl focus:ring-2 focus:ring-orange-500 transition-all" value={menuSearch} onChange={(e) => setMenuSearch(e.target.value)} />
          <i className="fas fa-search absolute left-5 top-1/2 -translate-y-1/2 text-gray-300"></i>
        </div>

        <div className="space-y-4">
          {filteredMenu.map(item => (
            <div key={item.id} className="bg-white rounded-3xl p-4 sm:p-6 border flex flex-col sm:flex-row items-center gap-6 group">
              <img src={item.image} className="w-24 h-24 rounded-2xl object-cover" alt="" />
              <div className="flex-1 text-center sm:text-left">
                <h4 className="font-black text-gray-900 text-lg">{item.name}</h4>
                <p className="text-orange-500 font-bold">₹{item.price}</p>
                <span className={`text-[10px] font-black px-2 py-0.5 rounded-full uppercase tracking-widest ${item.inStock ? 'bg-green-50 text-green-600' : 'bg-red-50 text-red-600'}`}>{item.inStock ? 'In Stock' : 'Out of Stock'}</span>
              </div>
              <div className="flex items-center gap-2">
                <button onClick={() => onToggleStock(item.id)} className={`px-4 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest border-2 transition-all ${item.inStock ? 'bg-green-500 border-green-500 text-white' : 'bg-white border-gray-100 text-gray-400'}`}>{item.inStock ? 'In Stock' : 'Out of Stock'}</button>
                <button onClick={() => setEditingItem(item)} className="w-11 h-11 bg-gray-50 text-gray-500 rounded-xl flex items-center justify-center hover:bg-orange-50 transition-all"><i className="fas fa-edit"></i></button>
                <button onClick={() => confirm(`Delete ${item.name}?`) && onDeleteItem(item.id)} className="w-11 h-11 bg-red-50 text-red-500 rounded-xl flex items-center justify-center hover:bg-red-500 hover:text-white transition-all"><i className="fas fa-trash-alt"></i></button>
              </div>
            </div>
          ))}
        </div>

        {showAddModal && (
          <div className="fixed inset-0 bg-black/40 backdrop-blur-sm z-50 flex items-center justify-center p-4">
            <div className="bg-white w-full max-w-md rounded-[2.5rem] p-8 shadow-2xl animate-in zoom-in-95">
              <div className="flex justify-between items-center mb-8">
                <h3 className="text-2xl font-black">Add Dish</h3>
                <button onClick={() => setShowAddModal(false)}><i className="fas fa-times text-xl text-gray-400"></i></button>
              </div>
              <form onSubmit={handleAddSubmit} className="space-y-4">
                <input type="text" placeholder="Name" className="w-full px-5 py-3.5 bg-gray-50 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none font-bold" value={newProduct.name} onChange={e => setNewProduct({...newProduct, name: e.target.value})} required />
                <div className="grid grid-cols-2 gap-4">
                  <input type="number" placeholder="Price" className="w-full px-5 py-3.5 bg-gray-50 rounded-2xl focus:ring-2 focus:ring-orange-500 outline-none font-bold" value={newProduct.price} onChange={e => setNewProduct({...newProduct, price: parseInt(e.target.value)})} required />
                  <select className="w-full px-5 py-3.5 bg-gray-50 rounded-2xl font-bold" value={newProduct.category} onChange={e => setNewProduct({...newProduct, category: e.target.value})}>
                    <option>Rice</option><option>Noodles</option><option>Breads</option><option>Specials</option><option>Drinks</option>
                  </select>
                </div>
                <input type="url" placeholder="Image URL" className="w-full px-5 py-3.5 bg-gray-50 rounded-2xl font-bold" value={newProduct.image} onChange={e => setNewProduct({...newProduct, image: e.target.value})} />
                <button type="submit" className="w-full bg-orange-500 text-white py-4 rounded-2xl font-bold shadow-xl hover:bg-orange-600 transition-all">Add to Menu</button>
              </form>
            </div>
          </div>
        )}

        {editingItem && (
          <div className="fixed inset-0 bg-black/40 backdrop-blur-sm z-50 flex items-center justify-center p-4">
            <div className="bg-white w-full max-w-md rounded-[2.5rem] p-8 shadow-2xl animate-in zoom-in-95">
              <div className="flex justify-between items-center mb-8">
                <h3 className="text-2xl font-black">Edit Dish</h3>
                <button onClick={() => setEditingItem(null)}><i className="fas fa-times text-xl text-gray-400"></i></button>
              </div>
              <form onSubmit={handleEditSubmit} className="space-y-4">
                <input type="text" className="w-full px-5 py-3.5 bg-gray-50 rounded-2xl font-bold" value={editingItem.name} onChange={e => setEditingItem({...editingItem, name: e.target.value})} />
                <div className="grid grid-cols-2 gap-4">
                  <input type="number" className="w-full px-5 py-3.5 bg-gray-50 rounded-2xl font-bold" value={editingItem.price} onChange={e => setEditingItem({...editingItem, price: parseInt(e.target.value)})} />
                  <select className="w-full px-5 py-3.5 bg-gray-50 rounded-2xl font-bold" value={editingItem.category} onChange={e => setEditingItem({...editingItem, category: e.target.value})}>
                    <option>Rice</option><option>Noodles</option><option>Breads</option><option>Specials</option><option>Drinks</option>
                  </select>
                </div>
                <input type="url" className="w-full px-5 py-3.5 bg-gray-50 rounded-2xl font-bold" value={editingItem.image} onChange={e => setEditingItem({...editingItem, image: e.target.value})} />
                <button type="submit" className="w-full bg-orange-500 text-white py-4 rounded-2xl font-bold shadow-xl hover:bg-orange-600 transition-all">Update Dish</button>
              </form>
            </div>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="p-4 sm:p-8 lg:p-12 max-w-4xl mx-auto">
      <div className="flex flex-col items-center text-center mb-12">
        <div className="w-28 h-28 sm:w-36 sm:h-36 rounded-full border-4 border-orange-50 p-1 mb-6"><img src={user.user_metadata?.avatar_url || `https://i.pravatar.cc/150?u=${user.id}`} className="w-full h-full rounded-full object-cover" alt="" /></div>
        <h3 className="text-3xl font-black text-gray-800">{user.user_metadata?.full_name || user.email?.split('@')[0]}</h3>
        <p className="text-gray-500 text-sm">{user.email}</p>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="space-y-6">
          <button onClick={() => setView('history')} className="w-full py-5 bg-white border rounded-3xl font-bold flex items-center px-6 space-x-4 shadow-sm group transition-all"><div className="w-12 h-12 bg-orange-50 text-orange-500 rounded-2xl flex items-center justify-center"><i className="fas fa-truck-fast"></i></div><div className="text-left"><span className="block font-black">Track Orders</span><span className="text-[10px] text-gray-400 uppercase">View Status</span></div></button>
